export enum Priority {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
}

export enum LifeAreaType {
  CAREER = 'Career',
  HEALTH = 'Health',
  FINANCE = 'Finance',
