  icon: string;
  color: string;
}

export interface SubGoal {
  id: string;
  title: string;
  completed: boolean;
}

export interface Goal {
  id: string;
  areaId: string;
  title: string;
  description: string;
  priority: Priority;
  targetDate: string;
  progress: number;
  subGoals: SubGoal[];
}

export interface Task {
