import { AlertCircle, ArrowUpRight, CheckCircle2, MoreHorizontal } from 'lucide-react';

interface DashboardProps {
  goals: Goal[];
  tasks: Task[];
  habits: Habit[];
  toggleTask: (id: string) => void;
  getWeeklyLoadStatus: () => any;
  getGoalRisk: (goal: Goal) => string;
}

const Dashboard: React.FC<DashboardProps> = ({ goals, tasks, habits, toggleTask, getWeeklyLoadStatus, getGoalRisk }) => {
  const load = getWeeklyLoadStatus();
  const today = new Date().toISOString().split('T')[0];
  const todaysTasks = tasks.filter(t => t.date.startsWith(today)).slice(0, 3);
  const activeGoals = goals.slice(0, 3);

  return (
    <div className="space-y-8">
      {/* Welcome Header */}
      <div>
        <h2 className="text-3xl font-bold text-slate-900">Good morning, Alex.</h2>
        <p className="text-slate-500 mt-1">You have {tasks.filter(t => !t.completed).length} items on your radar for today.</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-green-50 text-green-600 rounded-lg"><CheckCircle2 size={24} /></span>
            <span className="text-xs font-bold text-green-600 px-2 py-1 bg-green-50 rounded-full">+12% vs last wk</span>
          </div>
          <p className="text-slate-500 text-sm font-medium">Daily Completion</p>
          <div className="flex items-end gap-2 mt-1">
            <h3 className="text-3xl font-bold text-slate-900">84%</h3>
            <div className="flex-1 h-2 bg-slate-100 rounded-full mb-2 overflow-hidden">
              <div className="h-full bg-green-500 w-[84%]"></div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-blue-50 text-blue-600 rounded-lg"><AlertCircle size={24} /></span>
            {load.isOverloaded && (
              <span className="text-xs font-bold text-amber-600 px-2 py-1 bg-amber-50 rounded-full">Overload Detected</span>
