          <Plus size={18} />
          New Life Goal
        </button>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {areas.map(area => {
          const areaGoals = goals.filter(g => g.areaId === area);
          const info = LIFE_AREAS_INFO[area as keyof typeof LIFE_AREAS_INFO];

          return (
            <div key={area} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
              <div className="p-5 flex items-center justify-between border-b border-slate-100 bg-slate-50/50">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-lg ${info.color}`}>
                    {info.icon}
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-900">{area}</h3>
                    <p className="text-xs text-slate-500">{areaGoals.length} Active Goals</p>
                  </div>
                </div>
                <button className="text-slate-400 hover:text-slate-600">
                  <Plus size={20} />
                </button>
              </div>

              <div className="divide-y divide-slate-100">
                {areaGoals.length > 0 ? (
                  areaGoals.map(goal => (
                    <div key={goal.id} className="p-4">
                      <div className="flex items-start gap-3 group">
                        <button 
                          onClick={() => toggleExpand(goal.id)}
                          className="mt-1 text-slate-400 hover:text-slate-600"
                        >
                          {expanded.includes(goal.id) ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
                        </button>
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <h4 className="font-semibold text-slate-800 text-lg">{goal.title}</h4>
                            <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider ${
                              goal.priority === Priority.HIGH ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-500'
                            }`}>
                              {goal.priority}
                            </span>
                          </div>
                          <p className="text-sm text-slate-500 mt-1">{goal.description}</p>

                          <div className="mt-4 flex items-center gap-8">
                            <div className="flex-1 max-w-xs">
                              <div className="flex justify-between text-xs mb-1">
                                <span className="font-medium text-slate-400">Progress</span>
                                <span className="font-bold text-slate-700">{goal.progress}%</span>
                              </div>
                              <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                                <div className="h-full bg-[#6B8E7B]" style={{ width: `${goal.progress}%` }}></div>
                              </div>
                            </div>
                            <div className="text-xs text-slate-400">
                              <span className="font-medium">Target:</span>
                              <span className="ml-1 font-semibold text-slate-600">{new Date(goal.targetDate).toLocaleDateString('en-US', { month: 'short', year: 'numeric' })}</span>
                            </div>
                          </div>

                          {expanded.includes(goal.id) && (
                            <div className="mt-6 ml-4 space-y-3 border-l-2 border-slate-50 pl-6 animate-in slide-in-from-left-2 duration-300">
                              {goal.subGoals.map(sg => (
                                <div key={sg.id} className="flex items-center gap-3">
                                  <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-colors ${
                                    sg.completed ? 'bg-[#6B8E7B] border-[#6B8E7B] text-white' : 'border-slate-200'
                                  }`}>
                                    {sg.completed && <Plus size={12} className="rotate-45" />}
                                  </div>
                                  <span className={`text-sm ${sg.completed ? 'text-slate-400 line-through' : 'text-slate-700 font-medium'}`}>{sg.title}</span>
                                </div>
                              ))}
                              <button className="text-xs text-[#6B8E7B] font-bold hover:underline flex items-center gap-1 mt-2">
