import React from 'react';
import { Goal, Task, Habit, Priority } from '../types';
import { LIFE_AREAS_INFO } from '../constants';
import { AlertCircle, ArrowUpRight, CheckCircle2, MoreHorizontal, Circle } from 'lucide-react';

interface DashboardProps {
  goals: Goal[];
  tasks: Task[];
  habits: Habit[];
  toggleTask: (id: string) => void;
  getWeeklyLoadStatus: () => any;
  getGoalRisk: (goal: Goal) => string;
}

const Dashboard: React.FC<DashboardProps> = ({ goals, tasks, habits, toggleTask, getWeeklyLoadStatus, getGoalRisk }) => {
  const load = getWeeklyLoadStatus();
  const today = new Date().toISOString().split('T')[0];
  const todaysTasks = tasks.filter(t => t.date.startsWith(today));

  const activeTasks = todaysTasks.filter(t => !t.completed);
  const completedTasks = todaysTasks.filter(t => t.completed);

  const activeGoals = goals.slice(0, 3);

  const TaskItem = ({ task }: { task: Task }) => (
    <div key={task.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 transition-colors">
      <button 
        onClick={() => toggleTask(task.id)}
        className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-300 ${
          task.completed ? 'bg-green-500 border-green-500 text-white' : 'border-slate-300 hover:border-[#6B8E7B]'
        }`}
      >
        {task.completed ? <CheckCircle2 size={16} /> : <Circle size={14} className="text-transparent" />}
      </button>
      <div className="flex-1">
        <p className={`font-medium transition-all ${task.completed ? 'line-through text-slate-400' : 'text-slate-800'}`}>{task.title}</p>
        <div className="flex items-center gap-3 mt-1 text-xs text-slate-400">
          <span className="flex items-center gap-1">
            <div className={`w-1.5 h-1.5 rounded-full ${
              task.priority === Priority.HIGH ? 'bg-red-400' : task.priority === Priority.MEDIUM ? 'bg-amber-400' : 'bg-slate-400'
            }`}></div>
            {task.priority}
          </span>
          <span>•</span>
          <span>{task.estimatedHours}h</span>
        </div>
      </div>
      <button className="text-slate-300 hover:text-slate-500">
        <MoreHorizontal size={18} />
      </button>
    </div>
  );

  return (
    <div className="space-y-8">
      {/* Welcome Header */}
      <div>
        <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Good morning, Alex.</h2>
        <p className="text-slate-500 mt-1 font-medium">You have {activeTasks.length} active tasks left for today.</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-green-50 text-green-600 rounded-lg"><CheckCircle2 size={24} /></span>
            <span className="text-xs font-bold text-green-600 px-2 py-1 bg-green-50 rounded-full">+12% vs last wk</span>
          </div>
          <p className="text-slate-500 text-sm font-medium">Daily Completion</p>
          <div className="flex items-end gap-2 mt-1">
            <h3 className="text-3xl font-bold text-slate-900">
              {todaysTasks.length > 0 ? Math.round((completedTasks.length / todaysTasks.length) * 100) : 0}%
            </h3>
            <div className="flex-1 h-2 bg-slate-100 rounded-full mb-2 overflow-hidden">
              <div 
                className="h-full bg-green-500 transition-all duration-1000" 
                style={{ width: `${todaysTasks.length > 0 ? (completedTasks.length / todaysTasks.length) * 100 : 0}%` }}
              ></div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-blue-50 text-blue-600 rounded-lg"><AlertCircle size={24} /></span>
            {load.isOverloaded && (
              <span className="text-xs font-bold text-amber-600 px-2 py-1 bg-amber-50 rounded-full">Overload Detected</span>
            )}
          </div>
          <p className="text-slate-500 text-sm font-medium">Weekly Capacity</p>
          <div className="mt-1">
            <h3 className="text-3xl font-bold text-slate-900">{load.totalHours.toFixed(1)}h <span className="text-lg text-slate-400 font-normal">/ {load.limit.toFixed(1)}h</span></h3>
            <p className="text-xs text-slate-400 mt-1">Based on {load.limit.toFixed(1)}h daily allocation</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-purple-50 text-purple-600 rounded-lg"><ArrowUpRight size={24} /></span>
            <span className="text-xs font-bold text-purple-600 px-2 py-1 bg-purple-50 rounded-full">3 Goals Active</span>
          </div>
          <p className="text-slate-500 text-sm font-medium">Goal Velocity</p>
          <h3 className="text-3xl font-bold text-slate-900">High</h3>
          <p className="text-xs text-slate-400 mt-1">Tracking towards 80% completion by EOY</p>
        </div>
      </div>

      {/* Today's Focus - Split Dashboards */}
      <section className="space-y-4">
        <div className="flex items-center justify-between">
          <h3 className="text-xl font-bold text-slate-900">Today's Focus</h3>
          <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">{todaysTasks.length} Total Tasks</div>
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Active Section */}
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full">
            <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/30">
              <h4 className="font-bold text-slate-700 flex items-center gap-2">
                <Circle size={12} className="text-[#1E3A5F] fill-[#1E3A5F]" />
