            <button className="text-sm text-blue-600 font-medium hover:underline">Manage Vision</button>
          </div>
          <div className="space-y-4">
            {activeGoals.map(goal => {
              const risk = getGoalRisk(goal);
              return (
                <div key={goal.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm relative overflow-hidden group">
                  {risk === 'HIGH' && (
                    <div className="absolute top-0 right-0 px-3 py-1 bg-red-50 text-red-600 text-[10px] font-bold uppercase tracking-wider rounded-bl-lg">
                      At Risk
                    </div>
                  )}
                  <div className="flex items-start gap-3">
                    <div className={`p-2 rounded-lg ${LIFE_AREAS_INFO[goal.areaId as keyof typeof LIFE_AREAS_INFO].color}`}>
                      {LIFE_AREAS_INFO[goal.areaId as keyof typeof LIFE_AREAS_INFO].icon}
                    </div>
                    <div className="flex-1">
                      <h4 className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors">{goal.title}</h4>
                      <p className="text-xs text-slate-400 mt-1 uppercase tracking-tight font-semibold">Target: {new Date(goal.targetDate).toLocaleDateString()}</p>
                      <div className="mt-4">
                        <div className="flex justify-between text-xs mb-1">
                          <span className="font-medium text-slate-500">Progress</span>
                          <span className="font-bold text-slate-900">{goal.progress}%</span>
                        </div>
                        <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
                          <div 
                            className={`h-full transition-all duration-700 ${risk === 'HIGH' ? 'bg-red-400' : 'bg-blue-500'}`}
                            style={{ width: `${goal.progress}%` }}
                          ></div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </section>

        <section className="space-y-4">
          <h3 className="text-lg font-bold text-slate-900">Habit Streaks</h3>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            {habits.map(habit => (
              <div key={habit.id} className="bg-white p-4 rounded-xl border border-slate-200 flex items-center justify-between shadow-sm hover:border-slate-300 transition-all">
                <div>
                  <p className="font-semibold text-slate-800 text-sm">{habit.name}</p>
                  <div className="flex items-center gap-1 mt-1">
                    <span className="text-xs text-slate-400">Streak:</span>
                    <span className="text-xs font-bold text-orange-500 flex items-center gap-0.5">🔥 {habit.streak}</span>
                  </div>
                </div>
                <button 
                  onClick={() => {}} 
                  className={`w-8 h-8 rounded-full border flex items-center justify-center transition-all ${
                    habit.completedToday ? 'bg-green-500 border-green-500 text-white shadow-md' : 'border-slate-200 text-slate-300'
                  }`}
                >
                  <CheckCircle2 size={18} />
                </button>
              </div>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
