import { Plus, ChevronDown, ChevronRight, X, Calendar, Type, AlignLeft, Target, CheckCircle2 } from 'lucide-react';

interface VisionProps {
  goals: Goal[];
  addGoal: (goal: Goal) => void;
  addSubGoal: (goalId: string, title: string) => void;
  toggleSubGoal: (goalId: string, subGoalId: string) => void;
}

const Vision: React.FC<VisionProps> = ({ goals, addGoal, addSubGoal, toggleSubGoal }) => {
  const [expanded, setExpanded] = useState<string[]>([]);
  const [isAddingGoal, setIsAddingGoal] = useState(false);
