          </div>
          <div className="w-12 h-12 relative flex items-center justify-center">
            <svg className="w-full h-full transform -rotate-90">
              <circle cx="24" cy="24" r="20" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-slate-100" />
              <circle cx="24" cy="24" r="20" stroke="currentColor" strokeWidth="4" fill="transparent" strokeDasharray={126} strokeDashoffset={126 - (126 * (todaysTasks.length > 0 ? completedTasks.length / todaysTasks.length : 0))} className="text-[#6B8E7B] transition-all duration-1000" />
            </svg>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow group">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-green-50 text-green-600 rounded-lg group-hover:bg-green-100 transition-colors"><CheckCircle2 size={24} /></span>
            <span className="text-xs font-bold text-green-600 px-2 py-1 bg-green-50 rounded-full">Winning</span>
          </div>
          <p className="text-slate-500 text-sm font-medium">Completed Today</p>
          <h3 className="text-3xl font-bold text-slate-900 mt-1">{completedTasks.length}</h3>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow group">
