import React, { useState, useEffect, useRef } from 'react';
import { Goal, Priority, LifeAreaType, SubGoal } from '../types';
import { LIFE_AREAS_INFO } from '../constants';
import { Plus, ChevronDown, ChevronRight, X, Calendar, Type, AlignLeft, Target, CheckCircle2, AlertTriangle, Clock } from 'lucide-react';

interface VisionProps {
  goals: Goal[];
  highlightedId: string | null;
  addGoal: (goal: Goal) => void;
  updateGoal: (id: string, updates: Partial<Goal>) => void;
  addSubGoal: (goalId: string, title: string) => void;
  toggleSubGoal: (goalId: string, subGoalId: string) => void;
}

const Vision: React.FC<VisionProps> = ({ goals, highlightedId, addGoal, updateGoal, addSubGoal, toggleSubGoal }) => {
  const [expanded, setExpanded] = useState<string[]>([]);
  const [isAddingGoal, setIsAddingGoal] = useState(false);
  const [milestoneInputs, setMilestoneInputs] = useState<{ [goalId: string]: string }>({});
  const [editingDeadline, setEditingDeadline] = useState<string | null>(null);
  const scrollRef = useRef<{ [key: string]: HTMLDivElement | null }>({});

  // Form State
  const [newGoal, setNewGoal] = useState({
    title: '',
    description: '',
    areaId: LifeAreaType.CAREER,
    priority: Priority.MEDIUM,
    targetDate: new Date().toISOString().split('T')[0]
  });

  useEffect(() => {
    if (highlightedId && scrollRef.current[highlightedId]) {
      setExpanded(prev => prev.includes(highlightedId) ? prev : [...prev, highlightedId]);
      setTimeout(() => {
        scrollRef.current[highlightedId]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 100);
    }
  }, [highlightedId]);

  const toggleExpand = (id: string) => {
    setExpanded(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const handleCreateGoal = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newGoal.title.trim()) return;

    const goal: Goal = {
      id: `g-${Date.now()}`,
      ...newGoal,
      progress: 0,
      subGoals: []
    };

    addGoal(goal);
    setIsAddingGoal(false);
    setNewGoal({
      title: '',
      description: '',
      areaId: LifeAreaType.CAREER,
      priority: Priority.MEDIUM,
      targetDate: new Date().toISOString().split('T')[0]
    });
  };

  const handleAddMilestone = (goalId: string) => {
    const title = milestoneInputs[goalId];
    if (title && title.trim()) {
      addSubGoal(goalId, title.trim());
      setMilestoneInputs(prev => ({ ...prev, [goalId]: '' }));
    }
  };

  const isOverdue = (goal: Goal) => {
    if (goal.progress === 100) return false;
    const today = new Date();
    today.setHours(0,0,0,0);
    const target = new Date(goal.targetDate);
    target.setHours(0,0,0,0);
    return target < today;
  };

  const areas = Object.values(LifeAreaType);

  return (
    <div className="space-y-8 relative">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Vision & Strategic Goals</h2>
          <p className="text-slate-500 mt-1 font-medium">Define your North Star across every dimension of life.</p>
        </div>
        <button 
          onClick={() => setIsAddingGoal(true)}
          className="bg-[#1E3A5F] text-white px-5 py-2.5 rounded-xl flex items-center justify-center gap-2 hover:bg-blue-900 transition-all shadow-lg hover:shadow-blue-900/20 active:scale-95"
        >
          <Plus size={18} />
          New Life Goal
        </button>
      </div>

      {/* Categories Grid */}
      <div className="grid grid-cols-1 gap-6">
        {areas.map(area => {
          const areaGoals = goals.filter(g => g.areaId === area);
          const info = LIFE_AREAS_INFO[area as keyof typeof LIFE_AREAS_INFO];

          return (
            <div key={area} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm transition-all hover:border-slate-300">
              <div className="p-5 flex items-center justify-between border-b border-slate-100 bg-slate-50/30">
                <div className="flex items-center gap-3">
                  <div className={`p-2.5 rounded-xl ${info.color} shadow-sm`}>
                    {info.icon}
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-900">{area}</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{areaGoals.length} Active Objectives</p>
                  </div>
                </div>
                <button 
                  onClick={() => {
                    setNewGoal(prev => ({ ...prev, areaId: area as LifeAreaType }));
                    setIsAddingGoal(true);
                  }}
                  className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-lg transition-all"
                >
                  <Plus size={20} />
                </button>
              </div>

              <div className="divide-y divide-slate-100">
                {areaGoals.length > 0 ? (
                  areaGoals.map(goal => {
                    const overdue = isOverdue(goal);
                    const isHighlighted = highlightedId === goal.id;
                    return (
                      <div 
                        key={goal.id} 
                        ref={el => scrollRef.current[goal.id] = el}
                        className={`p-5 transition-all duration-500 border-l-4 ${
                          isHighlighted ? 'bg-blue-50/50 border-blue-500 ring-2 ring-blue-100' : 'border-transparent'
                        }`}
                      >
                        <div className="flex items-start gap-4 group">
                          <button 
                            onClick={() => toggleExpand(goal.id)}
                            className="mt-1 text-slate-300 hover:text-slate-600 transition-colors"
                          >
                            {expanded.includes(goal.id) ? <ChevronDown size={22} /> : <ChevronRight size={22} />}
                          </button>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-3">
                              <h4 className="font-bold text-slate-800 text-lg group-hover:text-blue-600 transition-colors truncate">{goal.title}</h4>
                              <span className={`text-[9px] font-black px-2 py-0.5 rounded uppercase tracking-tighter ${
                                goal.priority === Priority.HIGH ? 'bg-red-50 text-red-600' : 
                                goal.priority === Priority.MEDIUM ? 'bg-amber-50 text-amber-600' : 'bg-slate-100 text-slate-500'
                              }`}>
                                {goal.priority}
                              </span>
                              {overdue && (
                                <span className="flex items-center gap-1 text-[9px] font-black px-2 py-0.5 rounded uppercase tracking-tighter bg-red-100 text-red-700 animate-pulse">
                                  <AlertTriangle size={10} /> Overdue
                                </span>
                              )}
                            </div>
                            <p className="text-sm text-slate-500 mt-1 line-clamp-2">{goal.description}</p>

                            <div className="mt-5 flex flex-wrap items-center gap-x-8 gap-y-3">
                              <div className="flex-1 max-w-xs min-w-[200px]">
                                <div className="flex justify-between text-[10px] font-bold mb-1.5 uppercase tracking-wider text-slate-400">
                                  <span>Execution progress</span>
                                  <span className="text-slate-700">{goal.progress}%</span>
                                </div>
                                <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                                  <div 
                                    className={`h-full transition-all duration-1000 ${overdue ? 'bg-red-400' : 'bg-[#6B8E7B]'}`} 
                                    style={{ width: `${goal.progress}%` }}
                                  ></div>
                                </div>
                              </div>
                              <div className="flex items-center gap-4">
                                <div className={`text-[10px] font-bold uppercase tracking-widest flex items-center gap-2 ${overdue ? 'text-red-600' : 'text-slate-400'}`}>
                                  <Calendar size={14} />
                                  Deadline: <span className={overdue ? 'font-black' : 'text-slate-700'}>{new Date(goal.targetDate).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}</span>
                                </div>

                                {overdue && editingDeadline !== goal.id && (
                                  <button 
                                    onClick={() => setEditingDeadline(goal.id)}
                                    className="text-[10px] font-black text-blue-600 hover:text-blue-800 uppercase tracking-widest flex items-center gap-1 bg-blue-50 px-2 py-1 rounded"
                                  >
                                    <Clock size={12} /> Extend Date
                                  </button>
                                )}

                                {editingDeadline === goal.id && (
                                  <div className="flex items-center gap-2 animate-in slide-in-from-right-2 duration-200">
                                    <input 
                                      type="date" 
                                      className="text-[10px] font-bold border border-slate-200 rounded px-2 py-1 outline-none focus:ring-1 focus:ring-blue-500"
                                      defaultValue={goal.targetDate}
                                      onChange={(e) => {
                                        updateGoal(goal.id, { targetDate: e.target.value });
                                        setEditingDeadline(null);
                                      }}
                                    />
                                    <button onClick={() => setEditingDeadline(null)} className="text-slate-400 hover:text-slate-600">
                                      <X size={14} />
                                    </button>
                                  </div>
                                )}
                              </div>
                            </div>

                            {expanded.includes(goal.id) && (
                              <div className="mt-6 ml-2 space-y-4 border-l-2 border-slate-100 pl-6 animate-in slide-in-from-left-2 duration-300">
                                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Actionable Subgoals</div>
                                {goal.subGoals.map(sg => (
                                  <div key={sg.id} className="flex items-center gap-3 group/sub">
                                    <button 
                                      onClick={() => toggleSubGoal(goal.id, sg.id)}
                                      className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                        sg.completed ? 'bg-[#6B8E7B] border-[#6B8E7B] text-white' : 'border-slate-200 group-hover/sub:border-slate-300'
                                      }`}
                                    >
                                      {sg.completed && <CheckCircle2 size={12} />}
                                    </button>
                                    <span className={`text-sm ${sg.completed ? 'text-slate-400 line-through' : 'text-slate-700 font-medium'}`}>{sg.title}</span>
                                  </div>
                                ))}

                                <div className="flex items-center gap-2 pt-2">
                                  <input 
                                    type="text" 
                                    placeholder="Enter new milestone..."
                                    value={milestoneInputs[goal.id] || ''}
                                    onChange={(e) => setMilestoneInputs(prev => ({ ...prev, [goal.id]: e.target.value }))}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddMilestone(goal.id)}
                                    className="text-sm bg-slate-50 border border-slate-200 rounded-lg px-3 py-1.5 focus:ring-1 focus:ring-[#6B8E7B] outline-none flex-1 max-w-xs transition-all"
                                  />
                                  <button 
                                    onClick={() => handleAddMilestone(goal.id)}
                                    className="text-[11px] bg-[#6B8E7B] text-white px-3 py-2 rounded-lg font-black hover:bg-[#5a7b69] flex items-center gap-1.5 transition-all active:scale-95"
                                  >
                                    <Plus size={14} /> ADD
                                  </button>
                                </div>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    );
                  })
                ) : (
                  <div className="p-10 text-center">
                    <div className="w-12 h-12 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center mx-auto mb-3">
                      <Target size={24} />
                    </div>
                    <p className="text-slate-400 italic text-sm font-medium">No strategic goals set for {area}.</p>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Goal Creation Modal */}
      {isAddingGoal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" onClick={() => setIsAddingGoal(false)}></div>

          <div className="relative bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="bg-[#1E3A5F] px-8 py-6 text-white flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold tracking-tight">New Strategic Goal</h3>
                <p className="text-blue-200/70 text-xs font-medium mt-0.5">Define your target and priority</p>
              </div>
              <button onClick={() => setIsAddingGoal(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleCreateGoal} className="p-8 space-y-6">
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Type size={14} /> Goal Title
                </label>
                <input 
                  autoFocus
                  required
                  type="text" 
                  value={newGoal.title}
                  onChange={e => setNewGoal({...newGoal, title: e.target.value})}
                  placeholder="e.g., Become a Senior Architect"
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
                />
              </div>

              <div className="space-y-2">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <AlignLeft size={14} /> Context & Vision
                </label>
                <textarea 
                  rows={3}
                  value={newGoal.description}
                  onChange={e => setNewGoal({...newGoal, description: e.target.value})}
                  placeholder="Why does this matter? What does success look like?"
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all resize-none"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Life Area</label>
                  <select 
                    value={newGoal.areaId}
                    onChange={e => setNewGoal({...newGoal, areaId: e.target.value as LifeAreaType})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-3 text-sm focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 outline-none"
                  >
                    {areas.map(area => (
                      <option key={area} value={area}>{area}</option>
                    ))}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Priority</label>
                  <select 
                    value={newGoal.priority}
                    onChange={e => setNewGoal({...newGoal, priority: e.target.value as Priority})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-3 py-3 text-sm focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 outline-none"
                  >
                    {Object.values(Priority).map(p => (
                      <option key={p} value={p}>{p}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Calendar size={14} /> Target Deadline
                </label>
                <input 
                  type="date" 
                  value={newGoal.targetDate}
                  onChange={e => setNewGoal({...newGoal, targetDate: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
                />
              </div>

              <div className="pt-4 flex gap-3">
                <button 
                  type="button"
                  onClick={() => setIsAddingGoal(false)}
                  className="flex-1 bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold py-3 rounded-xl transition-all"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="flex-[2] bg-[#6B8E7B] hover:bg-[#5a7b69] text-white font-bold py-3 rounded-xl shadow-lg shadow-green-900/10 transition-all active:scale-95"
                >
                  Create Objective
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Vision;

import React, { useState, useEffect, useRef } from 'react';
import { Goal, Task, Habit, Priority } from '../types';
import { LIFE_AREAS_INFO } from '../constants';
import { AlertCircle, ArrowUpRight, CheckCircle2, MoreHorizontal, Circle, ListTodo, Plus, CornerDownLeft, ChevronDown } from 'lucide-react';

interface DashboardProps {
  goals: Goal[];
  tasks: Task[];
  habits: Habit[];
  highlightedId: string | null;
  toggleTask: (id: string) => void;
  toggleHabit: (id: string) => void;
  addTask: (title: string, priority: Priority, goalId?: string) => void;
  getWeeklyLoadStatus: () => any;
  getGoalRisk: (goal: Goal) => string;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  goals, 
  tasks, 
  habits, 
  highlightedId,
  toggleTask, 
  toggleHabit,
  addTask, 
  getWeeklyLoadStatus, 
  getGoalRisk 
}) => {
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>(Priority.MEDIUM);
  const scrollRef = useRef<{ [key: string]: HTMLDivElement | null }>({});

  const load = getWeeklyLoadStatus();
  const today = new Date().toISOString().split('T')[0];
  const todaysTasks = tasks.filter(t => t.date.startsWith(today));

  const activeTasks = todaysTasks.filter(t => !t.completed);
  const completedTasks = todaysTasks.filter(t => t.completed);

  const activeGoals = goals.slice(0, 3);

  useEffect(() => {
    if (highlightedId && scrollRef.current[highlightedId]) {
      scrollRef.current[highlightedId]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [highlightedId]);

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTaskTitle.trim()) {
      addTask(newTaskTitle.trim(), newTaskPriority);
      setNewTaskTitle('');
      setNewTaskPriority(Priority.MEDIUM);
    }
  };

  const TaskItem = ({ task }: { task: Task }) => (
    <div 
      key={task.id} 
      // Fix: Callback refs must return void or a cleanup function. Wrapping the assignment in braces ensures void return.
      ref={el => { scrollRef.current[task.id] = el; }}
      className={`p-3.5 flex items-center gap-3.5 transition-all duration-500 group border-l-4 ${
        highlightedId === task.id ? 'bg-yellow-50 border-yellow-400 ring-2 ring-yellow-200' : 'hover:bg-slate-50 border-transparent'
      }`}
    >
      <button 
        onClick={() => toggleTask(task.id)}
        className={`w-5.5 h-5.5 rounded-full border-2 flex items-center justify-center transition-all duration-300 transform group-hover:scale-105 ${
          task.completed ? 'bg-green-500 border-green-500 text-white' : 'border-slate-300 hover:border-[#6B8E7B]'
        }`}
      >
        {task.completed ? <CheckCircle2 size={14} /> : <Circle size={12} className="text-transparent" />}
      </button>
      <div className="flex-1 min-w-0">
        <p className={`text-sm font-medium transition-all truncate ${task.completed ? 'line-through text-slate-400' : 'text-slate-800'}`}>{task.title}</p>
        <div className="flex items-center gap-2 mt-0.5 text-[10px] text-slate-400 font-semibold uppercase tracking-tight">
          <span className="flex items-center gap-1">
            <div className={`w-1 h-1 rounded-full ${
              task.priority === Priority.HIGH ? 'bg-red-400' : task.priority === Priority.MEDIUM ? 'bg-amber-400' : 'bg-slate-400'
            }`}></div>
            {task.priority}
          </span>
          <span>•</span>
          <span>{task.estimatedHours}h</span>
        </div>
      </div>
      <button className="text-slate-300 hover:text-slate-500 opacity-0 group-hover:opacity-100 transition-opacity">
        <MoreHorizontal size={16} />
      </button>
    </div>
  );

  return (
    <div className="space-y-8 pb-12">
      {/* Welcome Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Good morning, Alex.</h2>
          <p className="text-slate-500 mt-1 font-medium">Your progress is the result of consistent daily intentions.</p>
        </div>
        <div className="bg-white px-5 py-3 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
          <div className="text-right">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Today's Progress</p>
            <p className="text-xl font-black text-slate-900">{todaysTasks.length > 0 ? Math.round((completedTasks.length / todaysTasks.length) * 100) : 0}%</p>
          </div>
          <div className="w-12 h-12 relative flex items-center justify-center">
            <svg className="w-full h-full transform -rotate-90">
              <circle cx="24" cy="24" r="20" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-slate-100" />
              <circle cx="24" cy="24" r="20" stroke="currentColor" strokeWidth="4" fill="transparent" strokeDasharray={126} strokeDashoffset={126 - (126 * (todaysTasks.length > 0 ? completedTasks.length / todaysTasks.length : 0))} className="text-[#6B8E7B] transition-all duration-1000" />
            </svg>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow group">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-green-50 text-green-600 rounded-lg group-hover:bg-green-100 transition-colors"><CheckCircle2 size={24} /></span>
            <span className="text-xs font-bold text-green-600 px-2 py-1 bg-green-50 rounded-full">Winning</span>
          </div>
          <p className="text-slate-500 text-sm font-medium">Completed Today</p>
          <h3 className="text-3xl font-bold text-slate-900 mt-1">{completedTasks.length}</h3>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow group">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-blue-50 text-blue-600 rounded-lg group-hover:bg-blue-100 transition-colors"><AlertCircle size={24} /></span>
            {load.isOverloaded && (
              <span className="text-xs font-bold text-amber-600 px-2 py-1 bg-amber-50 rounded-full animate-pulse">Overload</span>
            )}
          </div>
          <p className="text-slate-500 text-sm font-medium">Time Used</p>
          <div className="mt-1">
            <h3 className="text-3xl font-bold text-slate-900">{load.totalHours.toFixed(1)}h <span className="text-lg text-slate-400 font-normal">Est.</span></h3>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow group">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-purple-50 text-purple-600 rounded-lg group-hover:bg-purple-100 transition-colors"><ArrowUpRight size={24} /></span>
          </div>
          <p className="text-slate-500 text-sm font-medium">Habit Streak</p>
          <h3 className="text-3xl font-bold text-slate-900 mt-1">12 <span className="text-lg text-slate-400 font-normal">Days</span></h3>
        </div>
      </div>

      <div className="space-y-6">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-xl font-bold text-slate-900 flex items-center gap-2">
            <ListTodo size={20} className="text-[#1E3A5F]" />
            Today's Focus
          </h3>
          <div className="flex gap-4">
             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-blue-500"></div>
                {activeTasks.length} Active
             </div>
             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                {completedTasks.length} Done
             </div>
          </div>
        </div>

        {/* Side-by-Side Horizontal Dashboard */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
          {/* Active Section */}
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-[500px]">
            <div className="px-6 py-4 border-b border-slate-100 bg-white sticky top-0 z-10">
              <div className="flex items-center justify-between mb-4">
                <h4 className="font-bold text-slate-800">Active Tasks</h4>
                <div className="flex gap-2">
                  {(Object.keys(Priority) as (keyof typeof Priority)[]).map((p) => (
                    <button
                      key={p}
                      type="button"
                      onClick={() => setNewTaskPriority(Priority[p])}
                      className={`text-[9px] font-black px-2 py-0.5 rounded uppercase tracking-tighter transition-all ${
                        newTaskPriority === Priority[p]
                          ? Priority[p] === Priority.HIGH ? 'bg-red-500 text-white' : Priority[p] === Priority.MEDIUM ? 'bg-amber-500 text-white' : 'bg-slate-500 text-white'
                          : 'bg-slate-100 text-slate-400 hover:bg-slate-200'
                      }`}
                    >
                      {p}
                    </button>
                  ))}
                </div>
              </div>
              <form onSubmit={handleAddTask} className="relative group">
                <div className="absolute inset-y-0 left-3 flex items-center text-slate-400 group-focus-within:text-[#6B8E7B] transition-colors">
                  <Plus size={16} />
                </div>
                <input 
                  type="text" 
                  value={newTaskTitle}
                  onChange={(e) => setNewTaskTitle(e.target.value)}
                  placeholder="Capture new task..."
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl py-2.5 pl-10 pr-10 text-sm outline-none focus:ring-2 focus:ring-[#6B8E7B]/20 focus:border-[#6B8E7B] transition-all"
                />
                {newTaskTitle && (
                  <button type="submit" className="absolute inset-y-0 right-3 flex items-center text-[#6B8E7B]">
                    <CornerDownLeft size={16} />
                  </button>
                )}
              </form>
            </div>
            <div className="divide-y divide-slate-50 overflow-y-auto">
              {activeTasks.length > 0 ? (
                activeTasks.map(task => <TaskItem key={task.id} task={task} />)
              ) : (
                <div className="flex-1 flex flex-col items-center justify-center p-12 text-center h-full">
                  <div className="w-14 h-14 bg-green-50 text-green-500 rounded-full flex items-center justify-center mb-3">
                    <CheckCircle2 size={28} />
                  </div>
                  <p className="text-slate-500 font-semibold text-sm">Clear Horizon</p>
                  <p className="text-slate-400 text-xs mt-1">Add a task above to start your flow.</p>
                </div>
              )}
            </div>
          </div>

          {/* Completed Section */}
          <div className="bg-slate-50/30 rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-[500px]">
            <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-white sticky top-0 z-10">
              <h4 className="font-bold text-slate-500">Completed Today</h4>
              <button className="text-[10px] font-bold text-slate-400 hover:text-slate-600 tracking-widest">CLEAR ALL</button>
            </div>
            <div className="divide-y divide-slate-100 overflow-y-auto">
              {completedTasks.length > 0 ? (
                completedTasks.map(task => <TaskItem key={task.id} task={task} />)
              ) : (
                <div className="flex-1 flex flex-col items-center justify-center p-12 text-center h-full">
                  <div className="w-14 h-14 bg-slate-100 text-slate-300 rounded-full flex items-center justify-center mb-3">
                    <ListTodo size={24} />
                  </div>
                  <p className="text-slate-400 font-medium text-sm">Momentum Building...</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Strategic Goals & Daily Rituals */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <section className="space-y-4">
          <div className="flex items-center justify-between">
