                            className={`h-full transition-all duration-700 ${risk === 'HIGH' ? 'bg-red-400' : 'bg-[#6B8E7B]'}`}
                            style={{ width: `${goal.progress}%` }}
                          ></div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
