        <section className="space-y-4">
          <h3 className="text-lg font-bold text-slate-900">Daily Rituals</h3>
          <div className="grid grid-cols-1 gap-3">
            {habits.map(habit => (
              <div key={habit.id} className="bg-white p-4 rounded-xl border border-slate-200 flex items-center justify-between shadow-sm hover:border-slate-300 transition-all group">
                <div className="flex items-center gap-3">
                  <div className={`w-2 h-2 rounded-full ${habit.completedToday ? 'bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.3)]' : 'bg-slate-200'}`}></div>
