    <div className="space-y-8 relative">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Vision & Strategic Goals</h2>
          <p className="text-slate-500 mt-1 font-medium">Define your North Star across every dimension of life.</p>
        </div>
        <button 
          onClick={() => setIsAddingGoal(true)}
          className="bg-[#1E3A5F] text-white px-5 py-2.5 rounded-xl flex items-center justify-center gap-2 hover:bg-blue-900 transition-all shadow-lg hover:shadow-blue-900/20 active:scale-95"
        >
          <Plus size={18} />
          New Life Goal
        </button>
      </div>

      {/* Categories Grid */}
