                                  >
                                    <Clock size={12} /> Extend Date
                                  </button>
                                )}

                                {editingDeadline === goal.id && (
                                  <div className="flex items-center gap-2 animate-in slide-in-from-right-2 duration-200">
                                    <input 
                                      type="date" 
                                      className="text-[10px] font-bold border border-slate-200 rounded px-2 py-1 outline-none focus:ring-1 focus:ring-blue-500"
                                      defaultValue={goal.targetDate}
                                      onChange={(e) => {
                                        updateGoal(goal.id, { targetDate: e.target.value });
                                        setEditingDeadline(null);
                                      }}
                                    />
                                    <button onClick={() => setEditingDeadline(null)} className="text-slate-400 hover:text-slate-600">
                                      <X size={14} />
                                    </button>
                                  </div>
                                )}
                              </div>
                            </div>

                            {expanded.includes(goal.id) && (
                              <div className="mt-6 ml-2 space-y-4 border-l-2 border-slate-100 pl-6 animate-in slide-in-from-left-2 duration-300">
                                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Actionable Subgoals</div>
                                {goal.subGoals.map(sg => (
                                  <div key={sg.id} className="flex items-center gap-3 group/sub">
                                    <button 
                                      onClick={() => toggleSubGoal(goal.id, sg.id)}
                                      className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                                        sg.completed ? 'bg-[#6B8E7B] border-[#6B8E7B] text-white' : 'border-slate-200 group-hover/sub:border-slate-300'
                                      }`}
                                    >
                                      {sg.completed && <CheckCircle2 size={12} />}
                                    </button>
                                    <span className={`text-sm ${sg.completed ? 'text-slate-400 line-through' : 'text-slate-700 font-medium'}`}>{sg.title}</span>
                                  </div>
