import React, { useState, useEffect, useRef } from 'react';
import { NAV_ITEMS } from '../constants';
import { View, User, Goal, Task, Decision, Priority } from '../types';
import { Search, Bell, LogOut, Target, ListTodo, Scale, X, Command, Zap, AlertCircle, Info, CheckCircle2 } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  currentView: View;
  setView: (view: View) => void;
  user: User;
  goals: Goal[];
  tasks: Task[];
  decisions: Decision[];
  triggerHighlight: (id: string, view?: View) => void;
}

interface Notification {
  id: string;
  type: 'risk' | 'info' | 'success';
  title: string;
  message: string;
  timestamp: string;
}

const Layout: React.FC<LayoutProps> = ({ children, currentView, setView, user, goals, tasks, decisions, triggerHighlight }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showResults, setShowResults] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const searchRef = useRef<HTMLDivElement>(null);
  const notifRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Derived Notifications Logic
  const notifications: Notification[] = React.useMemo(() => {
    const list: Notification[] = [];

    // Check for Overdue Goals
    const today = new Date();
    today.setHours(0,0,0,0);

    goals.forEach(goal => {
      const target = new Date(goal.targetDate);
      target.setHours(0,0,0,0);
      if (target < today && goal.progress < 100) {
        list.push({
          id: `notif-goal-${goal.id}`,
          type: 'risk',
          title: 'Goal Overdue',
          message: `"${goal.title}" has passed its deadline. Please extend or complete.`,
          timestamp: 'Just now'
        });
      } else if (goal.progress < 30 && (target.getTime() - today.getTime()) < 1000 * 60 * 60 * 24 * 7) {
        list.push({
          id: `notif-risk-${goal.id}`,
          type: 'info',
          title: 'At Risk',
          message: `Slow progress on "${goal.title}" with deadline approaching.`,
          timestamp: '1h ago'
        });
      }
    });

    // Check for workload overload (simplistic check)
    const todaysTasks = tasks.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]));
    const hours = todaysTasks.reduce((sum, t) => sum + t.estimatedHours, 0);
    if (hours > 8) {
      list.push({
        id: 'notif-workload',
        type: 'risk',
        title: 'Capacity Warning',
        message: `Today's schedule (${hours}h) exceeds your 8h threshold.`,
        timestamp: 'Just now'
      });
    }

    return list;
  }, [goals, tasks]);

  // Handle keyboard shortcut (⌘K or Ctrl+K)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        inputRef.current?.focus();
      }
      if (e.key === 'Escape') {
        setShowResults(false);
        setShowNotifications(false);
        inputRef.current?.blur();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Close overlays when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(e.target as Node)) {
        setShowResults(false);
      }
      if (notifRef.current && !notifRef.current.contains(e.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Filter logic
  const filteredGoals = searchTerm.trim() 
    ? goals.filter(g => g.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];
  const filteredTasks = searchTerm.trim() 
    ? tasks.filter(t => t.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];
  const filteredDecisions = searchTerm.trim() 
    ? decisions.filter(d => d.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];

  const filteredNav = searchTerm.trim()
    ? NAV_ITEMS.filter(item => item.label.toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  const totalResults = filteredGoals.length + filteredTasks.length + filteredDecisions.length + filteredNav.length;

  const handleItemSelect = (id: string, view: View) => {
    triggerHighlight(id, view);
    setSearchTerm('');
    setShowResults(false);
  };

  const handleNavSelect = (view: View) => {
    setView(view);
    setSearchTerm('');
    setShowResults(false);
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#F4F4F2]">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-200 flex flex-col z-20">
        <div className="p-6">
          <div className="flex items-center gap-2 mb-8">
            <div className="w-8 h-8 bg-[#6B8E7B] rounded-lg flex items-center justify-center text-white font-bold">L</div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">LifeOS</h1>
          </div>

          <nav className="space-y-1">
            {NAV_ITEMS.map((item) => (
              <button
                key={item.id}
                onClick={() => setView(item.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 ${
                  currentView === item.id 
                    ? 'bg-[#1E3A5F] text-white shadow-lg shadow-blue-900/10' 
                    : 'text-slate-500 hover:bg-slate-100 hover:text-slate-900'
                }`}
              >
                {item.icon}
                <span className="font-medium">{item.label}</span>
              </button>
            ))}
          </nav>
        </div>

        <div className="mt-auto p-4 border-t border-slate-100">
          <div className="flex items-center gap-3 p-2 rounded-xl bg-slate-50 border border-slate-100">
            <img src={user.avatar} alt={user.name} className="w-10 h-10 rounded-full border-2 border-white" />
            <div className="overflow-hidden">
              <p className="text-sm font-semibold text-slate-900 truncate">{user.name}</p>
              <p className="text-xs text-slate-500 truncate">{user.email}</p>
            </div>
            <button className="ml-auto text-slate-400 hover:text-slate-600">
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col relative z-10 overflow-hidden">
        {/* Top Header */}
        <header className="h-16 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 flex items-center justify-between sticky top-0 z-30">
          <div className="relative w-96" ref={searchRef}>
            <div className="flex items-center gap-4 bg-slate-100 px-4 py-2 rounded-full border border-slate-200 group focus-within:ring-2 focus-within:ring-[#6B8E7B]/20 focus-within:border-[#6B8E7B] transition-all">
              <Search size={18} className="text-slate-400 group-focus-within:text-[#6B8E7B]" />
              <input 
                ref={inputRef}
                type="text" 
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setShowResults(true);
                }}
                onFocus={() => setShowResults(true)}
                placeholder="Find goals, tasks, or views... (⌘K)" 
                className="bg-transparent border-none outline-none text-sm w-full"
              />
              {searchTerm && (
                <button onClick={() => setSearchTerm('')} className="text-slate-400 hover:text-slate-600">
                  <X size={14} />
                </button>
              )}
            </div>

            {/* Search Results Dropdown */}
            {showResults && searchTerm && (
              <div className="absolute top-full mt-2 w-full bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200 max-h-[400px] overflow-y-auto">
                {totalResults === 0 ? (
                  <div className="p-8 text-center">
                    <p className="text-slate-400 text-sm font-medium">No results found for "{searchTerm}"</p>
                  </div>
                ) : (
                  <div className="p-2 space-y-4">
                    {filteredNav.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">App Sections</div>
                        {filteredNav.map(item => (
                          <button 
                            key={item.id} 
                            onClick={() => handleNavSelect(item.id)}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <Zap size={16} className="text-purple-500" />
                            <span className="text-sm font-bold text-slate-700 group-hover:text-purple-600">{item.label}</span>
                          </button>
                        ))}
                      </div>
                    )}

                    {filteredGoals.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Strategic Goals</div>
                        {filteredGoals.map(g => (
                          <button 
                            key={g.id} 
                            onClick={() => handleItemSelect(g.id, 'vision')}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <Target size={16} className="text-blue-500" />
                            <span className="text-sm font-medium text-slate-700 group-hover:text-blue-600">{g.title}</span>
                          </button>
                        ))}
                      </div>
                    )}

                    {filteredTasks.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Active Tasks</div>
                        {filteredTasks.map(t => (
                          <button 
                            key={t.id} 
                            onClick={() => handleItemSelect(t.id, 'dashboard')}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <ListTodo size={16} className="text-[#6B8E7B]" />
                            <span className="text-sm font-medium text-slate-700 group-hover:text-[#6B8E7B]">{t.title}</span>
                          </button>
                        ))}
                      </div>
                    )}

                    {filteredDecisions.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Decisions</div>
                        {filteredDecisions.map(d => (
                          <button 
                            key={d.id} 
                            onClick={() => handleItemSelect(d.id, 'decisions')}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <Scale size={16} className="text-orange-500" />
                            <span className="text-sm font-medium text-slate-700 group-hover:text-orange-600">{d.title}</span>
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                )}
                <div className="bg-slate-50 px-4 py-2 border-t border-slate-100 flex items-center justify-between">
                   <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-400 uppercase">
                     <Command size={10} /> + K to focus
                   </div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase">
                     ESC to close
                   </div>
                </div>
              </div>
            )}
          </div>

          <div className="flex items-center gap-4">
            <div className="relative" ref={notifRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className={`p-2 rounded-full transition-colors relative ${showNotifications ? 'bg-slate-100 text-[#1E3A5F]' : 'text-slate-500 hover:bg-slate-100'}`}
              >
                <Bell size={20} />
                {notifications.length > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-red-500 rounded-full border-2 border-white flex items-center justify-center text-[8px] font-bold text-white">
                    {notifications.length}
                  </span>
                )}
              </button>

              {/* Notifications Panel */}
              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200 z-50">
                  <div className="px-5 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                    <h3 className="font-bold text-slate-800 text-sm">LifeOS Alerts</h3>
                    <span className="text-[10px] font-bold text-[#6B8E7B] bg-green-50 px-2 py-0.5 rounded-full uppercase tracking-tighter">System Normal</span>
                  </div>
                  <div className="max-h-[350px] overflow-y-auto divide-y divide-slate-100">
                    {notifications.length === 0 ? (
                      <div className="p-10 text-center">
                        <CheckCircle2 size={32} className="text-slate-200 mx-auto mb-2" />
                        <p className="text-slate-400 text-sm font-medium">All systems clear.</p>
                      </div>
                    ) : (
                      notifications.map(notif => (
                        <div key={notif.id} className="p-4 hover:bg-slate-50 transition-colors flex gap-3">
                          <div className={`mt-0.5 p-1.5 rounded-lg shrink-0 ${notif.type === 'risk' ? 'bg-red-50 text-red-600' : 'bg-blue-50 text-blue-600'}`}>
                            {notif.type === 'risk' ? <AlertCircle size={16} /> : <Info size={16} />}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex justify-between items-start gap-2">
                              <p className="text-sm font-bold text-slate-900 leading-tight truncate">{notif.title}</p>
                              <span className="text-[10px] text-slate-400 font-medium shrink-0">{notif.timestamp}</span>
                            </div>
                            <p className="text-xs text-slate-500 mt-1 leading-relaxed">{notif.message}</p>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                  <div className="px-5 py-3 border-t border-slate-100 bg-slate-50/50 text-center">
                    <button className="text-[10px] font-bold text-slate-400 hover:text-slate-600 uppercase tracking-widest">View Historical Logs</button>
                  </div>
                </div>
              )}
            </div>

            <div className="h-8 w-px bg-slate-200 mx-2"></div>
            <button 
              onClick={() => { inputRef.current?.focus(); }}
              className="bg-[#6B8E7B] hover:bg-[#5a7b69] text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm"
            >
              Quick Find
            </button>
          </div>
        </header>

        {/* Scrollable View Area */}
        <div className="flex-1 overflow-y-auto p-8 bg-[#F4F4F2]/50 scroll-smooth">
          <div className="max-w-6xl mx-auto animate-in fade-in slide-in-from-bottom-2 duration-500">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useRef } from 'react';
import { Goal, Task, Habit, Priority } from '../types';
import { LIFE_AREAS_INFO } from '../constants';
import { AlertCircle, ArrowUpRight, CheckCircle2, MoreHorizontal, Circle, ListTodo, Plus, CornerDownLeft, ChevronDown } from 'lucide-react';

interface DashboardProps {
  goals: Goal[];
  tasks: Task[];
  habits: Habit[];
  highlightedId: string | null;
  toggleTask: (id: string) => void;
  toggleHabit: (id: string) => void;
  addTask: (title: string, priority: Priority, goalId?: string) => void;
  getWeeklyLoadStatus: () => any;
  getGoalRisk: (goal: Goal) => string;
}

const Dashboard: React.FC<DashboardProps> = ({ 
  goals, 
  tasks, 
  habits, 
  highlightedId,
  toggleTask, 
  toggleHabit,
  addTask, 
  getWeeklyLoadStatus, 
  getGoalRisk 
}) => {
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>(Priority.MEDIUM);
  const scrollRef = useRef<{ [key: string]: HTMLDivElement | null }>({});

  const load = getWeeklyLoadStatus();
  const today = new Date().toISOString().split('T')[0];
  const todaysTasks = tasks.filter(t => t.date.startsWith(today));

  const activeTasks = todaysTasks.filter(t => !t.completed);
  const completedTasks = todaysTasks.filter(t => t.completed);

  const activeGoals = goals.slice(0, 3);

  useEffect(() => {
    if (highlightedId && scrollRef.current[highlightedId]) {
      scrollRef.current[highlightedId]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [highlightedId]);

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTaskTitle.trim()) {
      addTask(newTaskTitle.trim(), newTaskPriority);
      setNewTaskTitle('');
      setNewTaskPriority(Priority.MEDIUM);
    }
  };

  const TaskItem = ({ task }: { task: Task }) => (
    <div 
      key={task.id} 
      // Fix: Callback refs must return void or a cleanup function. Wrapping the assignment in braces ensures void return.
      ref={el => { scrollRef.current[task.id] = el; }}
      className={`p-3.5 flex items-center gap-3.5 transition-all duration-500 group border-l-4 ${
        highlightedId === task.id ? 'bg-yellow-50 border-yellow-400 ring-2 ring-yellow-200' : 'hover:bg-slate-50 border-transparent'
      }`}
    >
      <button 
        onClick={() => toggleTask(task.id)}
        className={`w-5.5 h-5.5 rounded-full border-2 flex items-center justify-center transition-all duration-300 transform group-hover:scale-105 ${
          task.completed ? 'bg-green-500 border-green-500 text-white' : 'border-slate-300 hover:border-[#6B8E7B]'
        }`}
      >
        {task.completed ? <CheckCircle2 size={14} /> : <Circle size={12} className="text-transparent" />}
      </button>
      <div className="flex-1 min-w-0">
        <p className={`text-sm font-medium transition-all truncate ${task.completed ? 'line-through text-slate-400' : 'text-slate-800'}`}>{task.title}</p>
        <div className="flex items-center gap-2 mt-0.5 text-[10px] text-slate-400 font-semibold uppercase tracking-tight">
          <span className="flex items-center gap-1">
            <div className={`w-1 h-1 rounded-full ${
              task.priority === Priority.HIGH ? 'bg-red-400' : task.priority === Priority.MEDIUM ? 'bg-amber-400' : 'bg-slate-400'
            }`}></div>
            {task.priority}
          </span>
          <span>•</span>
          <span>{task.estimatedHours}h</span>
        </div>
      </div>
      <button className="text-slate-300 hover:text-slate-500 opacity-0 group-hover:opacity-100 transition-opacity">
        <MoreHorizontal size={16} />
      </button>
    </div>
  );

  return (
    <div className="space-y-8 pb-12">
      {/* Welcome Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">Good morning, Alex.</h2>
          <p className="text-slate-500 mt-1 font-medium">Your progress is the result of consistent daily intentions.</p>
        </div>
        <div className="bg-white px-5 py-3 rounded-2xl border border-slate-200 shadow-sm flex items-center gap-4">
          <div className="text-right">
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Today's Progress</p>
            <p className="text-xl font-black text-slate-900">{todaysTasks.length > 0 ? Math.round((completedTasks.length / todaysTasks.length) * 100) : 0}%</p>
          </div>
          <div className="w-12 h-12 relative flex items-center justify-center">
            <svg className="w-full h-full transform -rotate-90">
              <circle cx="24" cy="24" r="20" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-slate-100" />
              <circle cx="24" cy="24" r="20" stroke="currentColor" strokeWidth="4" fill="transparent" strokeDasharray={126} strokeDashoffset={126 - (126 * (todaysTasks.length > 0 ? completedTasks.length / todaysTasks.length : 0))} className="text-[#6B8E7B] transition-all duration-1000" />
            </svg>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow group">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-green-50 text-green-600 rounded-lg group-hover:bg-green-100 transition-colors"><CheckCircle2 size={24} /></span>
            <span className="text-xs font-bold text-green-600 px-2 py-1 bg-green-50 rounded-full">Winning</span>
          </div>
          <p className="text-slate-500 text-sm font-medium">Completed Today</p>
          <h3 className="text-3xl font-bold text-slate-900 mt-1">{completedTasks.length}</h3>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow group">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-blue-50 text-blue-600 rounded-lg group-hover:bg-blue-100 transition-colors"><AlertCircle size={24} /></span>
            {load.isOverloaded && (
              <span className="text-xs font-bold text-amber-600 px-2 py-1 bg-amber-50 rounded-full animate-pulse">Overload</span>
            )}
          </div>
          <p className="text-slate-500 text-sm font-medium">Time Used</p>
          <div className="mt-1">
            <h3 className="text-3xl font-bold text-slate-900">{load.totalHours.toFixed(1)}h <span className="text-lg text-slate-400 font-normal">Est.</span></h3>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow group">
          <div className="flex justify-between items-start mb-4">
            <span className="p-2 bg-purple-50 text-purple-600 rounded-lg group-hover:bg-purple-100 transition-colors"><ArrowUpRight size={24} /></span>
          </div>
          <p className="text-slate-500 text-sm font-medium">Habit Streak</p>
          <h3 className="text-3xl font-bold text-slate-900 mt-1">12 <span className="text-lg text-slate-400 font-normal">Days</span></h3>
        </div>
      </div>

      <div className="space-y-6">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-xl font-bold text-slate-900 flex items-center gap-2">
            <ListTodo size={20} className="text-[#1E3A5F]" />
            Today's Focus
          </h3>
          <div className="flex gap-4">
             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-blue-500"></div>
                {activeTasks.length} Active
             </div>
             <div className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                {completedTasks.length} Done
             </div>
          </div>
        </div>

        {/* Side-by-Side Horizontal Dashboard */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
          {/* Active Section */}
          <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col max-h-[600px]">
            <div className="px-6 py-4 border-b border-slate-100 bg-white sticky top-0 z-10">
              <div className="flex items-center justify-between mb-4">
                <h4 className="font-bold text-slate-800">Active Tasks</h4>
                <div className="flex gap-2">
                  {(Object.keys(Priority) as (keyof typeof Priority)[]).map((p) => (
                    <button
                      key={p}
                      type="button"
                      onClick={() => setNewTaskPriority(Priority[p])}
                      className={`text-[9px] font-black px-2 py-0.5 rounded uppercase tracking-tighter transition-all ${
                        newTaskPriority === Priority[p]
                          ? Priority[p] === Priority.HIGH ? 'bg-red-50 text-white' : Priority[p] === Priority.MEDIUM ? 'bg-amber-50 text-white' : 'bg-slate-500 text-white'
                          : 'bg-slate-100 text-slate-400 hover:bg-slate-200'
                      }`}
                    >
                      {p}
                    </button>
                  ))}
                </div>
              </div>
              <form onSubmit={handleAddTask} className="relative group">
                <div className="absolute inset-y-0 left-3 flex items-center text-slate-400 group-focus-within:text-[#6B8E7B] transition-colors">
                  <Plus size={16} />
                </div>
                <input 
                  type="text" 
                  value={newTaskTitle}
                  onChange={(e) => setNewTaskTitle(e.target.value)}
                  placeholder="Capture new task..."
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl py-2.5 pl-10 pr-10 text-sm outline-none focus:ring-2 focus:ring-[#6B8E7B]/20 focus:border-[#6B8E7B] transition-all"
                />
                {newTaskTitle && (
                  <button type="submit" className="absolute inset-y-0 right-3 flex items-center text-[#6B8E7B]">
                    <CornerDownLeft size={16} />
                  </button>
                )}
              </form>
            </div>
            <div className="divide-y divide-slate-50 overflow-y-auto min-h-[100px]">
              {activeTasks.length > 0 ? (
                activeTasks.map(task => <TaskItem key={task.id} task={task} />)
              ) : (
                <div className="flex flex-col items-center justify-center p-12 text-center h-full">
                  <div className="w-14 h-14 bg-green-50 text-green-500 rounded-full flex items-center justify-center mb-3">
                    <CheckCircle2 size={28} />
                  </div>
                  <p className="text-slate-500 font-semibold text-sm">Clear Horizon</p>
                  <p className="text-slate-400 text-xs mt-1">Add a task above to start your flow.</p>
                </div>
              )}
            </div>
          </div>

          {/* Completed Section */}
          <div className="bg-slate-50/30 rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col max-h-[600px]">
            <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-white sticky top-0 z-10">
              <h4 className="font-bold text-slate-500">Completed Today</h4>
              <button className="text-[10px] font-bold text-slate-400 hover:text-slate-600 tracking-widest">CLEAR ALL</button>
            </div>
            <div className="divide-y divide-slate-100 overflow-y-auto min-h-[100px]">
              {completedTasks.length > 0 ? (
                completedTasks.map(task => <TaskItem key={task.id} task={task} />)
              ) : (
                <div className="flex flex-col items-center justify-center p-12 text-center h-full">
                  <div className="w-14 h-14 bg-slate-100 text-slate-300 rounded-full flex items-center justify-center mb-3">
                    <ListTodo size={24} />
                  </div>
                  <p className="text-slate-400 font-medium text-sm">Momentum Building...</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Strategic Goals & Daily Rituals */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <section className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-bold text-slate-900">Strategic Alignment</h3>
            <button className="text-sm text-blue-600 font-medium hover:underline">Vision Board</button>
          </div>
          <div className="space-y-4">
            {activeGoals.map(goal => {
              const risk = getGoalRisk(goal);
              return (
                <div key={goal.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm relative overflow-hidden group hover:shadow-md transition-all">
                  {risk === 'HIGH' && (
                    <div className="absolute top-0 right-0 px-3 py-1 bg-red-50 text-red-600 text-[10px] font-bold uppercase tracking-wider rounded-bl-lg">
                      At Risk
                    </div>
                  )}
                  <div className="flex items-start gap-4">
                    <div className={`p-2.5 rounded-xl ${LIFE_AREAS_INFO[goal.areaId as keyof typeof LIFE_AREAS_INFO].color}`}>
                      {LIFE_AREAS_INFO[goal.areaId as keyof typeof LIFE_AREAS_INFO].icon}
                    </div>
                    <div className="flex-1 min-w-0">
                      <h4 className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors truncate">{goal.title}</h4>
                      <div className="mt-3">
                        <div className="flex justify-between text-[10px] font-bold mb-1 uppercase tracking-wider">
                          <span className="text-slate-400">Completion</span>
