};

import React, { useState, useMemo } from 'react';
import { WeeklyPlan, LifeAreaType, Priority, Task } from '../types';
import { LIFE_AREAS_INFO } from '../constants';
import { 
  ChevronLeft, 
  ChevronRight, 
  Sparkles, 
  Plus, 
  CheckCircle2, 
  Circle, 
  AlertCircle, 
  Quote, 
  Smile, 
  Frown, 
  Meh, 
  Heart,
  TrendingUp,
  Brain
} from 'lucide-react';

interface PlannerProps {
  selectedWeekId: string;
  weeklyPlans: { [weekId: string]: WeeklyPlan };
  tasks: Task[];
  setSelectedWeekId: (id: string) => void;
  updateWeeklyPlan: (weekId: string, updates: Partial<WeeklyPlan>) => void;
  addTask: (title: string, priority: Priority, goalId?: string, date?: string, areaId?: LifeAreaType) => void;
  toggleTask: (id: string) => void;
}

const Planner: React.FC<PlannerProps> = ({ 
  selectedWeekId, 
  weeklyPlans, 
  tasks, 
  setSelectedWeekId, 
  updateWeeklyPlan,
  addTask,
  toggleTask
}) => {
  const currentPlan = weeklyPlans[selectedWeekId] || { weekId: selectedWeekId, intent: '', focus: '', priorities: [], allocatedHours: 40 };
  const [activeDayInput, setActiveDayInput] = useState<number | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');

  // Week Logic
  const getWeekDates = (weekId: string) => {
    const [year, week] = weekId.split('-W');
    const d = new Date(parseInt(year), 0, 1);
    const dayOffset = (parseInt(week) - 1) * 7;
    d.setDate(d.getDate() + dayOffset - (d.getDay() || 7) + 1);
    const dates = [];
    for (let i = 0; i < 7; i++) {
      const date = new Date(d);
      date.setDate(d.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = useMemo(() => getWeekDates(selectedWeekId), [selectedWeekId]);
  const dateRangeStr = `${weekDates[0].toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – ${weekDates[6].toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;

  const weekTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDate = new Date(t.date);
      return taskDate >= weekDates[0] && taskDate <= weekDates[6];
    });
  }, [tasks, weekDates]);

  // Balance Stats
  const areaBalance = useMemo(() => {
    const stats: Record<string, { count: number; completed: number }> = {};
    Object.values(LifeAreaType).forEach(area => stats[area] = { count: 0, completed: 0 });

    weekTasks.forEach(t => {
      const area = t.areaId || LifeAreaType.PERSONAL;
      stats[area].count++;
      if (t.completed) stats[area].completed++;
    });
    return stats;
  }, [weekTasks]);

  const handleWeekChange = (direction: number) => {
    const [year, week] = selectedWeekId.split('-W');
    let nextWeek = parseInt(week) + direction;
    let nextYear = parseInt(year);
    if (nextWeek > 52) { nextWeek = 1; nextYear++; }
    if (nextWeek < 1) { nextWeek = 52; nextYear--; }
    setSelectedWeekId(`${nextYear}-W${nextWeek}`);
  };

  const handleAddTask = (date: Date) => {
    if (newTaskTitle.trim()) {
      addTask(newTaskTitle, Priority.MEDIUM, undefined, date.toISOString());
      setNewTaskTitle('');
      setActiveDayInput(null);
    }
  };

  const updateReflection = (updates: Partial<WeeklyPlan['reflection']>) => {
    const currentReflection = currentPlan.reflection || { mood: 'Neutral', rating: 5, wentWell: '', toImprove: '' };
    updateWeeklyPlan(selectedWeekId, {
      reflection: { ...currentReflection, ...updates } as any
    });
  };

  return (
    <div className="space-y-10 pb-20 max-w-7xl mx-auto">
      {/* Header Section */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden animate-in fade-in slide-in-from-top-4 duration-500">
        <div className="p-8 flex flex-col md:flex-row items-center justify-between gap-8 bg-gradient-to-br from-white to-slate-50/50">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
              <button onClick={() => handleWeekChange(-1)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ChevronLeft size={20} /></button>
              <div className="text-center min-w-[140px]">
                <h2 className="text-sm font-black text-slate-400 uppercase tracking-widest">{selectedWeekId}</h2>
                <p className="text-lg font-bold text-slate-900">{dateRangeStr}</p>
              </div>
              <button onClick={() => handleWeekChange(1)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ChevronRight size={20} /></button>
            </div>
          </div>

          <div className="flex-1 max-w-md w-full">
            <div className="relative group">
              <Sparkles size={16} className="absolute -top-3 -left-3 text-amber-400 animate-bounce" />
              <input 
                type="text"
                placeholder="What is your primary intent for this week?"
                value={currentPlan.intent}
                onChange={(e) => updateWeeklyPlan(selectedWeekId, { intent: e.target.value })}
                className="w-full bg-transparent text-xl font-bold text-[#1E3A5F] border-b-2 border-slate-100 focus:border-[#6B8E7B] outline-none py-2 px-1 transition-all text-center"
              />
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2 text-center">Current Weekly Intent</p>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-4 bg-white/80 p-4 rounded-2xl border border-slate-100 shadow-sm italic text-slate-500 text-sm max-w-xs relative">
            <Quote size={16} className="absolute -top-2 -left-2 text-slate-200" />
            "Consistency is the playground of the unimaginative, but the foundation of the high performer."
          </div>
        </div>
      </div>

      {/* Balance Dashboard */}
      <section className="space-y-4">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <Heart size={14} className="text-rose-500" /> Weekly Balance Monitor
          </h3>
          <div className="flex gap-4">
            {Object.values(LifeAreaType).filter(a => areaBalance[a].count === 0).length > 0 && (
              <span className="flex items-center gap-1.5 text-[10px] font-black text-amber-600 animate-pulse bg-amber-50 px-2 py-1 rounded-full uppercase">
                <AlertCircle size={12} /> Imbalance Detected
              </span>
            )}
          </div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
          {Object.entries(LIFE_AREAS_INFO).map(([area, info]) => {
            const stats = areaBalance[area];
            const progress = stats.count > 0 ? (stats.completed / stats.count) * 100 : 0;
            return (
              <div key={area} className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all group">
                <div className="flex items-center justify-between mb-3">
                  <div className={`p-2 rounded-xl ${info.color} group-hover:scale-110 transition-transform`}>{info.icon}</div>
                  <span className="text-[10px] font-bold text-slate-400">{stats.completed}/{stats.count}</span>
                </div>
                <h4 className="text-xs font-bold text-slate-900 truncate">{area}</h4>
                <div className="mt-3 h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                  <div className={`h-full transition-all duration-1000 ${progress === 100 ? 'bg-green-500' : 'bg-[#6B8E7B]'}`} style={{ width: `${progress}%` }}></div>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {/* Daily Planner Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-7 gap-4 items-start">
        {weekDates.map((date, idx) => {
          const dateStr = date.toISOString().split('T')[0];
          const dayTasks = weekTasks.filter(t => t.date.startsWith(dateStr));
          const isToday = new Date().toISOString().split('T')[0] === dateStr;

          return (
            <div key={idx} className={`bg-white rounded-2xl border ${isToday ? 'border-blue-400 ring-2 ring-blue-50 shadow-lg' : 'border-slate-200'} shadow-sm flex flex-col min-h-[400px] transition-all overflow-hidden`}>
              <div className={`p-4 border-b border-slate-100 ${isToday ? 'bg-blue-50/50' : 'bg-slate-50/30'} flex justify-between items-center`}>
                <div>
                  <h4 className={`text-xs font-black uppercase tracking-widest ${isToday ? 'text-blue-600' : 'text-slate-400'}`}>{date.toLocaleDateString('en-US', { weekday: 'short' })}</h4>
                  <p className="text-sm font-bold text-slate-900">{date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</p>
                </div>
                {isToday && <span className="text-[8px] font-black bg-blue-600 text-white px-1.5 py-0.5 rounded-full uppercase">Today</span>}
              </div>

              <div className="flex-1 p-2 space-y-1 overflow-y-auto">
                {dayTasks.map(task => (
                  <button 
                    key={task.id} 
                    onClick={() => toggleTask(task.id)}
                    className={`w-full text-left p-2 rounded-xl text-xs flex items-start gap-2 transition-all group ${
                      task.completed ? 'bg-slate-50 text-slate-400' : 'hover:bg-slate-50'
                    }`}
                  >
                    <div className="mt-0.5">
                      {task.completed ? <CheckCircle2 size={12} className="text-green-500" /> : <Circle size={12} className="text-slate-300 group-hover:text-[#6B8E7B]" />}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className={`font-medium line-clamp-2 ${task.completed ? 'line-through' : 'text-slate-700'}`}>{task.title}</p>
                      <div className={`mt-1 flex items-center gap-1.5 text-[8px] font-black uppercase tracking-tighter ${
                        task.priority === Priority.HIGH ? 'text-red-500' : task.priority === Priority.MEDIUM ? 'text-amber-500' : 'text-green-500'
                      }`}>
                        {task.priority}
                      </div>
                    </div>
                  </button>
                ))}

                {activeDayInput === idx ? (
                  <div className="p-2 animate-in zoom-in-95 duration-200">
                    <input 
                      autoFocus
                      type="text" 
                      placeholder="Task name..."
                      value={newTaskTitle}
                      onChange={(e) => setNewTaskTitle(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleAddTask(date)}
                      className="w-full text-xs p-2 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-[#6B8E7B]"
                    />
                    <div className="flex justify-end gap-2 mt-2">
                      <button onClick={() => setActiveDayInput(null)} className="text-[10px] font-bold text-slate-400">Cancel</button>
                      <button onClick={() => handleAddTask(date)} className="text-[10px] font-bold text-blue-600">Add</button>
                    </div>
                  </div>
                ) : (
                  <button 
                    onClick={() => { setActiveDayInput(idx); setNewTaskTitle(''); }}
                    className="w-full p-2 rounded-xl border border-dashed border-slate-200 text-slate-400 hover:text-[#6B8E7B] hover:border-[#6B8E7B] transition-all flex items-center justify-center gap-1 text-[10px] font-bold mt-2"
                  >
                    <Plus size={12} /> ADD TASK
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Weekly Reflection Section */}
      <section className="bg-[#1E3A5F] text-white rounded-3xl p-10 shadow-2xl shadow-blue-900/20 relative overflow-hidden group">
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl group-hover:scale-150 transition-transform duration-1000"></div>
        <div className="relative z-10 grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
          <div>
            <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-white/10 rounded-xl backdrop-blur-md">
                <Brain size={24} className="text-blue-200" />
              </div>
              <h3 className="text-2xl font-bold">Weekly Reflection</h3>
            </div>
            <p className="text-blue-100/70 text-sm leading-relaxed mb-8">
              True learning happens when we pause to analyze our actions. Take a moment to close this loop before moving to the next cycle.
            </p>

            <div className="flex items-center gap-6 mb-8">
              <span className="text-xs font-bold text-blue-200/50 uppercase tracking-widest">Weekly Mood</span>
              <div className="flex gap-4">
                {[
                  { label: 'Great', icon: <Smile className="text-green-400" /> },
                  { label: 'Neutral', icon: <Meh className="text-blue-300" /> },
                  { label: 'Stressed', icon: <Frown className="text-rose-400" /> }
                ].map((mood) => (
                  <button 
                    key={mood.label}
                    onClick={() => updateReflection({ mood: mood.label })}
                    className={`p-3 rounded-2xl transition-all ${currentPlan.reflection?.mood === mood.label ? 'bg-white/20 scale-110 shadow-lg' : 'bg-white/5 hover:bg-white/10'}`}
                  >
                    {mood.icon}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-xs font-bold text-blue-200/50 uppercase">
                <span>Weekly Rating</span>
                <span className="text-blue-300">{currentPlan.reflection?.rating || 5}/10</span>
              </div>
              <input 
                type="range" min="1" max="10" 
                value={currentPlan.reflection?.rating || 5}
                onChange={(e) => updateReflection({ rating: parseInt(e.target.value) })}
                className="w-full accent-blue-400" 
              />
            </div>
          </div>

          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-blue-200/50 uppercase tracking-widest block">Wins & Progress</label>
              <textarea 
                placeholder="What went exceptionally well this week?"
                value={currentPlan.reflection?.wentWell || ''}
                onChange={(e) => updateReflection({ wentWell: e.target.value })}
                className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm text-white placeholder-white/20 outline-none focus:border-blue-400 transition-all resize-none"
                rows={3}
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-blue-200/50 uppercase tracking-widest block">Growth Opportunities</label>
              <textarea 
                placeholder="What will you adjust for the next cycle?"
                value={currentPlan.reflection?.toImprove || ''}
                onChange={(e) => updateReflection({ toImprove: e.target.value })}
                className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm text-white placeholder-white/20 outline-none focus:border-blue-400 transition-all resize-none"
                rows={3}
              />
            </div>
            <div className="flex items-center gap-3 p-4 bg-green-500/10 border border-green-500/20 rounded-2xl">
              <TrendingUp size={18} className="text-green-400" />
              <p className="text-xs text-green-100/70 font-medium">Your productivity score for this week is <span className="text-green-400 font-bold">84%</span>. You are outperforming your 4-week average.</p>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Planner;

import React from 'react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Vision from './pages/Vision';
import Decisions from './pages/Decisions';
import Analytics from './pages/Analytics';
import Planner from './pages/Planner';
import { useLifeOS } from './services/store';

const App: React.FC = () => {
  const { 
    currentView, 
    setView, 
    user, 
    goals, 
    tasks, 
    habits, 
    decisions, 
    weeklyPlans,
    selectedWeekId,
    highlightedId,
    triggerHighlight,
    toggleTask, 
    toggleHabit,
    addTask,
    addGoal,
    updateGoal,
    addSubGoal,
    toggleSubGoal,
    getWeeklyLoadStatus, 
    getGoalRisk,
    calculateDecisionScores,
    setSelectedWeekId,
    updateWeeklyPlan
  } = useLifeOS();

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return (
          <Dashboard 
            goals={goals} 
            tasks={tasks} 
            habits={habits} 
            highlightedId={highlightedId}
            toggleTask={toggleTask} 
            toggleHabit={toggleHabit}
            addTask={addTask}
            getWeeklyLoadStatus={getWeeklyLoadStatus}
            getGoalRisk={getGoalRisk}
          />
        );
      case 'vision':
        return (
          <Vision 
            goals={goals} 
            highlightedId={highlightedId}
            addGoal={addGoal} 
            updateGoal={updateGoal}
            addSubGoal={addSubGoal} 
            toggleSubGoal={toggleSubGoal} 
          />
        );
      case 'planner':
        return (
          <Planner 
            selectedWeekId={selectedWeekId}
            weeklyPlans={weeklyPlans}
            tasks={tasks}
            setSelectedWeekId={setSelectedWeekId}
            updateWeeklyPlan={updateWeeklyPlan}
            addTask={addTask}
            toggleTask={toggleTask}
          />
        );
      case 'decisions':
        return <Decisions decisions={decisions} calculateScores={calculateDecisionScores} />;
      case 'analytics':
        return <Analytics goals={goals} tasks={tasks} habits={habits} />;
      case 'execution':
        return (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
             <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4">🚀</div>
             <h2 className="text-xl font-bold text-slate-700">Daily Execution</h2>
             <p>A focused view of today's deep work blocks.</p>
