                    >
                      <div className="mt-0.5">
                        {task.completed ? <CheckCircle2 size={12} className="text-green-500" /> : <Circle size={12} className="text-slate-300 group-hover:text-[#6B8E7B]" />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className={`font-medium line-clamp-2 ${task.completed ? 'line-through' : 'text-slate-700'}`}>{task.title}</p>
                        <div className="mt-1 flex flex-wrap items-center gap-1.5">
                          <div className={`text-[8px] font-black uppercase tracking-tighter ${
                            task.priority === Priority.HIGH ? 'text-red-500' : task.priority === Priority.MEDIUM ? 'text-amber-500' : 'text-green-500'
                          }`}>
                            {task.priority}
                          </div>
                          <span className="text-[8px] text-slate-300">•</span>
                          <div className={`text-[8px] font-bold px-1 rounded ${areaInfo.color.split(' ')[0]} ${areaInfo.color.split(' ')[1]}`}>
                            {task.areaId || 'Personal'}
                          </div>
                        </div>
                      </div>
                    </button>
                  );
                })}

                {activeDayInput === idx ? (
                  <div className="p-2 animate-in zoom-in-95 duration-200 bg-slate-50 rounded-xl border border-slate-200 mt-2">
                    <input 
                      autoFocus
                      type="text" 
                      placeholder="Task name..."
                      value={newTaskTitle}
                      onChange={(e) => setNewTaskTitle(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleAddTask(date)}
                      className="w-full text-xs p-2 bg-white border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-[#6B8E7B]"
                    />

                    <div className="mt-3 space-y-2">
                      <div className="flex items-center justify-between">
                        <span className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Priority</span>
                        <div className="flex gap-1">
                          {(Object.keys(Priority) as (keyof typeof Priority)[]).map((p) => (
                            <button
                              key={p}
                              type="button"
                              onClick={() => setNewTaskPriority(Priority[p])}
                              className={`text-[8px] font-black px-1.5 py-0.5 rounded uppercase transition-all ${
                                newTaskPriority === Priority[p]
                                  ? Priority[p] === Priority.HIGH ? 'bg-red-500 text-white' : Priority[p] === Priority.MEDIUM ? 'bg-amber-500 text-white' : 'bg-green-500 text-white'
                                  : 'bg-white text-slate-400 border border-slate-200 hover:border-slate-300'
                              }`}
                            >
                              {p[0]}
                            </button>
                          ))}
                        </div>
                      </div>

                      <div className="flex items-center justify-between">
                        <span className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Area</span>
                        <select 
                          value={newTaskArea}
                          onChange={(e) => setNewTaskArea(e.target.value as LifeAreaType)}
                          className="text-[9px] bg-white border border-slate-200 rounded px-1 py-0.5 outline-none font-medium text-slate-600"
                        >
                          {Object.values(LifeAreaType).map(area => (
                            <option key={area} value={area}>{area}</option>
                          ))}
                        </select>
                      </div>
                    </div>

                    <div className="flex justify-end gap-2 mt-3 pt-2 border-t border-slate-100">
                      <button onClick={() => { setActiveDayInput(null); setNewTaskPriority(Priority.MEDIUM); }} className="text-[10px] font-bold text-slate-400 hover:text-slate-600">Cancel</button>
                      <button onClick={() => handleAddTask(date)} className="text-[10px] font-bold text-blue-600 hover:text-blue-800">Add</button>
                    </div>
                  </div>
                ) : (
                  <button 
                    onClick={() => { setActiveDayInput(idx); setNewTaskTitle(''); setNewTaskPriority(Priority.MEDIUM); }}
                    className="w-full p-2 rounded-xl border border-dashed border-slate-200 text-slate-400 hover:text-[#6B8E7B] hover:border-[#6B8E7B] transition-all flex items-center justify-center gap-1 text-[10px] font-bold mt-2"
                  >
                    <Plus size={12} /> ADD TASK
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Weekly Reflection Section */}
      <section className="bg-[#1E3A5F] text-white rounded-3xl p-10 shadow-2xl shadow-blue-900/20 relative overflow-hidden group">
