    calculateDecisionScores,
    setSelectedWeekId,
    updateWeeklyPlan
  } = useLifeOS();

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return (
          <Dashboard 
            goals={goals} 
            tasks={tasks} 
            habits={habits} 
            highlightedId={highlightedId}
            toggleTask={toggleTask} 
            toggleHabit={toggleHabit}
            addTask={addTask}
            getWeeklyLoadStatus={getWeeklyLoadStatus}
            getGoalRisk={getGoalRisk}
          />
        );
      case 'vision':
        return (
          <Vision 
            goals={goals} 
            highlightedId={highlightedId}
            addGoal={addGoal} 
            updateGoal={updateGoal}
            addSubGoal={addSubGoal} 
            toggleSubGoal={toggleSubGoal} 
          />
        );
      case 'planner':
        return (
          <Planner 
            selectedWeekId={selectedWeekId}
            weeklyPlans={weeklyPlans}
            tasks={tasks}
            goals={goals}
            setSelectedWeekId={setSelectedWeekId}
            updateWeeklyPlan={updateWeeklyPlan}
            addTask={addTask}
            toggleTask={toggleTask}
          />
        );
      case 'decisions':
        return <Decisions decisions={decisions} calculateScores={calculateDecisionScores} />;
      case 'analytics':
        return <Analytics goals={goals} tasks={tasks} habits={habits} />;
      case 'execution':
        return (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
             <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4">🚀</div>
             <h2 className="text-xl font-bold text-slate-700">Daily Execution</h2>
             <p>A focused view of today's deep work blocks.</p>
          </div>
        );
      default:
        return (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
             <h2 className="text-xl font-bold text-slate-700 italic">Module under construction</h2>
          </div>
        );
    }
  };

  return (
    <Layout 
      currentView={currentView} 
      setView={setView} 
      user={user}
      goals={goals}
      tasks={tasks}
      decisions={decisions}
      triggerHighlight={triggerHighlight}
    >
      {renderView()}
    </Layout>
  );
};

