            const stats = areaBalance[area];
            const progress = stats.count > 0 ? (stats.completed / stats.count) * 100 : 0;
            return (
              <div key={area} className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all group">
