                className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm text-white placeholder-white/20 outline-none focus:border-blue-400 transition-all resize-none"
                rows={3}
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-blue-200/50 uppercase tracking-widest block">Growth Opportunities</label>
              <textarea 
                placeholder="What will you adjust for the next cycle?"
                value={currentPlan.reflection?.toImprove || ''}
                onChange={(e) => updateReflection({ toImprove: e.target.value })}
                className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm text-white placeholder-white/20 outline-none focus:border-blue-400 transition-all resize-none"
                rows={3}
              />
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Planner;

import React, { useState, useEffect, useRef } from 'react';
import { NAV_ITEMS } from '../constants';
import { View, User, Goal, Task, Decision, Priority } from '../types';
import { Search, Bell, LogOut, Target, ListTodo, Scale, X, Command, Zap, AlertCircle, Info, CheckCircle2, History } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  currentView: View;
  setView: (view: View) => void;
  user: User;
  goals: Goal[];
  tasks: Task[];
  decisions: Decision[];
  triggerHighlight: (id: string, view?: View) => void;
}

interface Notification {
  id: string;
  type: 'risk' | 'info' | 'success' | 'alert';
  title: string;
  message: string;
  timestamp: string;
}

const Layout: React.FC<LayoutProps> = ({ children, currentView, setView, user, goals, tasks, decisions, triggerHighlight }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showResults, setShowResults] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const searchRef = useRef<HTMLDivElement>(null);
  const notifRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Derived Notifications Logic
  const notifications: Notification[] = React.useMemo(() => {
    const list: Notification[] = [];

    // 1. Check for Overdue Goals
    const today = new Date();
    today.setHours(0,0,0,0);

    goals.forEach(goal => {
      const target = new Date(goal.targetDate);
      target.setHours(0,0,0,0);
      if (target < today && goal.progress < 100) {
        list.push({
          id: `notif-goal-${goal.id}`,
          type: 'risk',
          title: 'Goal Overdue',
          message: `"${goal.title}" has passed its deadline. Please extend or complete.`,
          timestamp: 'Just now'
        });
      } else if (goal.progress < 30 && (target.getTime() - today.getTime()) < 1000 * 60 * 60 * 24 * 7) {
        list.push({
          id: `notif-risk-${goal.id}`,
          type: 'info',
          title: 'At Risk',
          message: `Slow progress on "${goal.title}" with deadline approaching.`,
          timestamp: '1h ago'
        });
      }
    });

    // 2. Check for Carried Forward Tasks (Uncompleted from past days)
    const carriedForwardTasks = tasks.filter(t => !t.completed && t.isCarriedForward);
    carriedForwardTasks.forEach(task => {
      list.push({
        id: `notif-task-carried-${task.id}`,
        type: 'alert',
        title: 'Unfinished Task',
        message: `"${task.title}" was not finished yesterday. It's waiting for you today.`,
        timestamp: 'Persistent'
      });
    });

    // 3. Check for workload overload (simplistic check)
    const todaysTasks = tasks.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]));
    const hours = todaysTasks.reduce((sum, t) => sum + t.estimatedHours, 0);
    if (hours > 8) {
      list.push({
        id: 'notif-workload',
        type: 'risk',
        title: 'Capacity Warning',
        message: `Today's schedule (${hours}h) exceeds your 8h threshold.`,
        timestamp: 'Just now'
      });
    }

    return list;
  }, [goals, tasks]);

  // Handle keyboard shortcut (⌘K or Ctrl+K)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        inputRef.current?.focus();
      }
      if (e.key === 'Escape') {
        setShowResults(false);
        setShowNotifications(false);
        inputRef.current?.blur();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Close overlays when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(e.target as Node)) {
        setShowResults(false);
      }
      if (notifRef.current && !notifRef.current.contains(e.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Filter logic
  const filteredGoals = searchTerm.trim() 
    ? goals.filter(g => g.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];
  const filteredTasks = searchTerm.trim() 
    ? tasks.filter(t => t.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];
  const filteredDecisions = searchTerm.trim() 
    ? decisions.filter(d => d.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];

  const filteredNav = searchTerm.trim()
    ? NAV_ITEMS.filter(item => item.label.toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  const totalResults = filteredGoals.length + filteredTasks.length + filteredDecisions.length + filteredNav.length;

  const handleItemSelect = (id: string, view: View) => {
    triggerHighlight(id, view);
    setSearchTerm('');
    setShowResults(false);
  };

  const handleNavSelect = (view: View) => {
    setView(view);
    setSearchTerm('');
    setShowResults(false);
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#F4F4F2]">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-200 flex flex-col z-20">
        <div className="p-6">
          <div className="flex items-center gap-2 mb-8">
            <div className="w-8 h-8 bg-[#6B8E7B] rounded-lg flex items-center justify-center text-white font-bold">L</div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">LifeOS</h1>
          </div>

          <nav className="space-y-1">
            {NAV_ITEMS.map((item) => (
              <button
                key={item.id}
                onClick={() => setView(item.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 ${
                  currentView === item.id 
                    ? 'bg-[#1E3A5F] text-white shadow-lg shadow-blue-900/10' 
                    : 'text-slate-500 hover:bg-slate-100 hover:text-slate-900'
                }`}
              >
                {item.icon}
                <span className="font-medium">{item.label}</span>
              </button>
            ))}
          </nav>
        </div>

        <div className="mt-auto p-4 border-t border-slate-100">
          <div className="flex items-center gap-3 p-2 rounded-xl bg-slate-50 border border-slate-100">
            <img src={user.avatar} alt={user.name} className="w-10 h-10 rounded-full border-2 border-white" />
            <div className="overflow-hidden">
              <p className="text-sm font-semibold text-slate-900 truncate">{user.name}</p>
              <p className="text-xs text-slate-500 truncate">{user.email}</p>
            </div>
            <button className="ml-auto text-slate-400 hover:text-slate-600">
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col relative z-10 overflow-hidden">
        {/* Top Header */}
        <header className="h-16 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 flex items-center justify-between sticky top-0 z-30">
          <div className="relative w-96" ref={searchRef}>
            <div className="flex items-center gap-4 bg-slate-100 px-4 py-2 rounded-full border border-slate-200 group focus-within:ring-2 focus-within:ring-[#6B8E7B]/20 focus-within:border-[#6B8E7B] transition-all">
              <Search size={18} className="text-slate-400 group-focus-within:text-[#6B8E7B]" />
              <input 
