                            'bg-blue-50 text-blue-600'
                          }`}>
                            {notif.type === 'risk' ? <AlertCircle size={16} /> : 
                             notif.type === 'alert' ? <History size={16} /> : 
                             <Info size={16} />}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex justify-between items-start gap-2">
                              <p className="text-sm font-bold text-slate-900 leading-tight truncate">{notif.title}</p>
                              <span className="text-[10px] text-slate-400 font-medium shrink-0">{notif.timestamp}</span>
