import { useState, useEffect, useCallback } from 'react';
import { Goal, Task, Habit, Decision, WeeklyPlan, User, View, Priority, SubGoal, WeeklyReflection, LifeAreaType } from '../types';
import { MOCK_USER, MOCK_GOALS, MOCK_TASKS, MOCK_HABITS, MOCK_DECISIONS } from '../mockData';

const STORAGE_KEY = 'lifeos_data_v1_planner';

interface AppState {
  user: User;
  goals: Goal[];
  tasks: Task[];
  habits: Habit[];
  decisions: Decision[];
  weeklyPlans: { [weekId: string]: WeeklyPlan };
  currentView: View;
  selectedWeekId: string;
}

const getWeekId = (date: Date) => {
  const d = new Date(date);
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + 4 - (d.getDay() || 7));
  const yearStart = new Date(d.getFullYear(), 0, 1);
  const weekNo = Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
  return `${d.getFullYear()}-W${weekNo}`;
};

export function useLifeOS() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    const initial = saved ? JSON.parse(saved) : INITIAL_STATE;
    return { ...initial, selectedWeekId: getWeekId(new Date()) };
  });

  const [highlightedId, setHighlightedId] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  // Carry Forward Logic: If a task's date is in the past and it's not completed, move it to TODAY
  const carryForwardTasks = useCallback(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayStr = today.toISOString().split('T')[0];

    setState(prev => {
      let changed = false;
      const updatedTasks = prev.tasks.map(task => {
        const taskDate = new Date(task.date);
        taskDate.setHours(0, 0, 0, 0);

        // Check if task is in the past AND not completed
        if (!task.completed && taskDate.getTime() < today.getTime()) {
          changed = true;
          // Preserve time if available
          const timePart = task.date.includes('T') ? task.date.split('T')[1] : '09:00:00.000Z';
          return {
            ...task,
            date: `${todayStr}T${timePart}`,
            isCarriedForward: true
          };
        }
        return task;
      });

      if (!changed) return prev;
      return { ...prev, tasks: updatedTasks };
    });
  }, []);

  // Run carry forward on mount, view changes, and check every minute for day roll-overs
  useEffect(() => {
    carryForwardTasks();
    const interval = setInterval(carryForwardTasks, 60000); // Check every minute
    return () => clearInterval(interval);
  }, [state.currentView, carryForwardTasks]);

  const setView = (view: View) => setState(prev => ({ ...prev, currentView: view }));

  const setSelectedWeekId = (id: string) => setState(prev => ({ ...prev, selectedWeekId: id }));

  const triggerHighlight = (id: string, view?: View) => {
    if (view) setView(view);
    setHighlightedId(id);
    setTimeout(() => setHighlightedId(null), 3000);
  };

  const toggleTask = (taskId: string) => {
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: !t.completed } : t)
    }));
  };

  const deleteTask = (taskId: string) => {
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== taskId)
    }));
  };

  const addTask = (title: string, priority: Priority = Priority.MEDIUM, goalId?: string, date?: string, areaId?: LifeAreaType) => {
    const newTask: Task = {
      id: `t-${Date.now()}`,
      title,
      goalId,
      areaId: areaId || LifeAreaType.PERSONAL,
      completed: false,
      date: date || new Date().toISOString(),
      estimatedHours: 1,
      priority
    };
    setState(prev => ({ ...prev, tasks: [newTask, ...prev.tasks] }));
  };

  const updateWeeklyPlan = (weekId: string, updates: Partial<WeeklyPlan>) => {
    setState(prev => {
      const existing = prev.weeklyPlans[weekId] || { 
        weekId, 
        intent: '', 
        focus: '', 
        priorities: [], 
        allocatedHours: 40 
      };
      return {
        ...prev,
        weeklyPlans: {
          ...prev.weeklyPlans,
          [weekId]: { ...existing, ...updates }
        }
      };
    });
  };

  const toggleHabit = (habitId: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === habitId ? { ...h, completedToday: !h.completedToday, streak: h.completedToday ? h.streak - 1 : h.streak + 1 } : h)
    }));
  };

  const addGoal = (goal: Goal) => {
    setState(prev => ({ ...prev, goals: [...prev.goals, goal] }));
  };

  const updateGoal = (id: string, updates: Partial<Goal>) => {
    setState(prev => ({
      ...prev,
      goals: prev.goals.map(g => g.id === id ? { ...g, ...updates } : g)
    }));
  };

  const addSubGoal = (goalId: string, title: string) => {
    setState(prev => ({
      ...prev,
      goals: prev.goals.map(g => {
        if (g.id !== goalId) return g;
        const newSubGoal: SubGoal = { id: `sg-${Date.now()}`, title, completed: false };
        const updatedSubGoals = [...g.subGoals, newSubGoal];
        const completedCount = updatedSubGoals.filter(sg => sg.completed).length;
        const progress = Math.round((completedCount / updatedSubGoals.length) * 100);
        return { ...g, subGoals: updatedSubGoals, progress };
      })
    }));
  };

  const toggleSubGoal = (goalId: string, subGoalId: string) => {
    setState(prev => ({
      ...prev,
      goals: prev.goals.map(g => {
        if (g.id !== goalId) return g;
        const updatedSubGoals = g.subGoals.map(sg => 
          sg.id === subGoalId ? { ...sg, completed: !sg.completed } : sg
        );
        const completedCount = updatedSubGoals.filter(sg => sg.completed).length;
        const progress = updatedSubGoals.length > 0 ? Math.round((completedCount / updatedSubGoals.length) * 100) : 0;
        return { ...g, subGoals: updatedSubGoals, progress };
      })
    }));
  };

  const addDecision = (decision: Decision) => {
    setState(prev => ({ ...prev, decisions: [decision, ...prev.decisions] }));
  };

  const getGoalRisk = (goal: Goal) => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const target = new Date(goal.targetDate);
    const diffDays = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    if (diffDays < 0 && goal.progress < 100) return 'OVERDUE';
    if (goal.progress < 50 && diffDays < 90) return 'HIGH';
    if (goal.progress < 75 && diffDays < 30) return 'MEDIUM';
    return 'LOW';
  };

  const getWeeklyLoadStatus = () => {
    const today = new Date().toISOString().split('T')[0];
    const todaysTasks = state.tasks.filter(t => t.date.startsWith(today));
    const totalHoursToday = todaysTasks.reduce((sum, t) => sum + t.estimatedHours, 0);
    const weeklyPlan = state.weeklyPlans[state.selectedWeekId];
    const dailyLimit = (weeklyPlan?.allocatedHours || 35) / 7;
    return {
      totalHours: totalHoursToday,
      limit: dailyLimit,
      isOverloaded: totalHoursToday > dailyLimit,
    };
  };

  const calculateDecisionScores = (decision: Decision) => {
    return decision.options.map(opt => {
      let total = 0;
      decision.criteria.forEach(crit => {
        total += (opt.scores[crit.id] || 0) * crit.weight;
      });
      return { ...opt, totalScore: total };
    }).sort((a, b) => b.totalScore - a.totalScore);
  };

  return {
    ...state,
    highlightedId,
    setView,
    setSelectedWeekId,
    updateWeeklyPlan,
    triggerHighlight,
    toggleTask,
    deleteTask,
    addTask,
    toggleHabit,
    addGoal,
    updateGoal,
    addSubGoal,
    toggleSubGoal,
    addDecision,
    getGoalRisk,
    getWeeklyLoadStatus,
    calculateDecisionScores,
  };
}

