                <div className="mt-3 h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                  <div className={`h-full transition-all duration-1000 ${progress === 100 ? 'bg-green-500' : 'bg-[#6B8E7B]'}`} style={{ width: `${progress}%` }}></div>
                </div>
