                        <span className="text-[8px] font-black text-slate-400 uppercase tracking-tighter">Area</span>
                        <select 
                          value={newTaskArea}
                          onChange={(e) => setNewTaskArea(e.target.value as LifeAreaType)}
                          className="text-[9px] bg-white border border-slate-200 rounded px-1 py-0.5 outline-none font-medium text-slate-600"
                        >
                          {Object.values(LifeAreaType).map(area => (
                            <option key={area} value={area}>{area}</option>
                          ))}
                        </select>
                      </div>
                    </div>

                    <div className="flex justify-end gap-2 mt-3 pt-2 border-t border-slate-100">
                      <button onClick={() => { setActiveDayInput(null); setNewTaskPriority(Priority.MEDIUM); }} className="text-[10px] font-bold text-slate-400 hover:text-slate-600">Cancel</button>
                      <button onClick={() => handleAddTask(date)} className="text-[10px] font-bold text-blue-600 hover:text-blue-800">Add</button>
                    </div>
                  </div>
                ) : (
                  <button 
                    onClick={() => { setActiveDayInput(idx); setNewTaskTitle(''); setNewTaskPriority(Priority.MEDIUM); }}
                    className="w-full p-2 rounded-xl border border-dashed border-slate-200 text-slate-400 hover:text-[#6B8E7B] hover:border-[#6B8E7B] transition-all flex items-center justify-center gap-1 text-[10px] font-bold mt-2"
                  >
                    <Plus size={12} /> ADD TASK
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Weekly Reflection Section */}
      <section className="bg-[#1E3A5F] text-white rounded-3xl p-10 shadow-2xl shadow-blue-900/20 relative overflow-hidden group">
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl group-hover:scale-150 transition-transform duration-1000"></div>
        <div className="relative z-10 grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
          <div>
            <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-white/10 rounded-xl backdrop-blur-md">
