  HEALTH = 'Health',
  FINANCE = 'Finance',
  LEARNING = 'Learning',
  RELATIONSHIPS = 'Relationships',
  PERSONAL = 'Personal',
}

export interface LifeArea {
  id: string;
  name: LifeAreaType;
  icon: string;
  color: string;
}

export interface SubGoal {
  id: string;
  title: string;
  completed: boolean;
}

export interface Goal {
  id: string;
  areaId: string;
  title: string;
  description: string;
  priority: Priority;
  targetDate: string;
  progress: number;
  subGoals: SubGoal[];
}

export interface Task {
  id: string;
  goalId?: string;
  areaId?: LifeAreaType;
  title: string;
  completed: boolean;
  date: string; // ISO string
  estimatedHours: number;
  priority: Priority;
  isCarriedForward?: boolean;
}

export interface Habit {
  id: string;
  name: string;
  streak: number;
  completedToday: boolean;
  history: { [date: string]: boolean };
}

export interface DecisionCriterion {
  id: string;
  name: string;
  weight: number; // 1-10
}

export interface DecisionOption {
  id: string;
  name: string;
  scores: { [criterionId: string]: number }; // 1-10
}

export interface Decision {
  id: string;
  title: string;
  description: string;
  criteria: DecisionCriterion[];
  options: DecisionOption[];
  createdAt: string;
}

export interface WeeklyReflection {
  mood: string;
  energyLevel: number;
  stressLevel: number;
  wins: string[];
  biggestWinIndex: number;
  drainedBy: string[];
  energizedBy: string[];
  lessonLearned: string;
  productivityRating: number;
  happinessRating: number;
  balanceRating: number;
  improvementFocus: string;
  noteToSelf: string;
}

export interface WeeklyPlan {
  weekId: string; // e.g., "2024-W42"
  intent: string;
  focus: string;
  reflection?: WeeklyReflection;
  priorities: string[];
  allocatedHours: number;
}

export interface User {
  id: string;
  name: string;
  email: string;
  avatar: string;
}

export type View = 'dashboard' | 'vision' | 'planner' | 'execution' | 'analytics' | 'decisions' | 'settings';

import React, { useState, useMemo } from 'react';
import { WeeklyPlan, LifeAreaType, Priority, Task, Goal, WeeklyReflection } from '../types';
import { LIFE_AREAS_INFO } from '../constants';
import { 
  ChevronLeft, 
  ChevronRight, 
  Sparkles, 
  Plus, 
  CheckCircle2, 
  Circle, 
  AlertCircle, 
  Quote, 
  Smile, 
  Frown, 
  Meh, 
  Heart,
  Brain,
  Zap,
  Trash2,
  Battery,
  CloudLightning,
  Sun,
  PenLine,
  Star,
  Trophy,
  Coffee,
  X
} from 'lucide-react';

interface PlannerProps {
  selectedWeekId: string;
  weeklyPlans: { [weekId: string]: WeeklyPlan };
  tasks: Task[];
  goals: Goal[];
  setSelectedWeekId: (id: string) => void;
  updateWeeklyPlan: (weekId: string, updates: Partial<WeeklyPlan>) => void;
  addTask: (title: string, priority: Priority, goalId?: string, date?: string, areaId?: LifeAreaType) => void;
  toggleTask: (id: string) => void;
  deleteTask: (id: string) => void;
}

const Planner: React.FC<PlannerProps> = ({ 
  selectedWeekId, 
  weeklyPlans, 
  tasks, 
  goals,
  setSelectedWeekId, 
  updateWeeklyPlan,
  addTask,
  toggleTask,
  deleteTask
}) => {
  const currentPlan = weeklyPlans[selectedWeekId] || { weekId: selectedWeekId, intent: '', focus: '', priorities: [], allocatedHours: 40 };

  const [activeDayInput, setActiveDayInput] = useState<number | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>(Priority.MEDIUM);
  const [newTaskArea, setNewTaskArea] = useState<LifeAreaType>(LifeAreaType.PERSONAL);

  const [customDrain, setCustomDrain] = useState('');
  const [customEnergizer, setCustomEnergizer] = useState('');

  // Reflection Constants
  const MOODS = [
    { label: 'Happy', emoji: '😊', color: 'text-green-500' },
    { label: 'Calm', emoji: '😌', color: 'text-blue-400' },
    { label: 'Neutral', emoji: '😐', color: 'text-slate-400' },
    { label: 'Stressed', emoji: '😫', color: 'text-amber-500' },
    { label: 'Sad', emoji: '😢', color: 'text-indigo-600' }
  ];

  const DRAIN_TAGS = ['Overplanning', 'Social Media', 'Poor Sleep', 'Distractions', 'Toxic Conversation', 'Health Issues'];
  const ENERGY_TAGS = ['Workout', 'Deep Work', 'Family Time', 'Learning', 'Friends', 'Self-care'];

  // Default values for new reflection
  const defaultReflection: WeeklyReflection = {
    mood: 'Neutral',
    energyLevel: 5,
    stressLevel: 3,
    wins: [],
    biggestWinIndex: -1,
    drainedBy: [],
    energizedBy: [],
    lessonLearned: '',
    productivityRating: 5,
    happinessRating: 5,
    balanceRating: 5,
    improvementFocus: '',
    noteToSelf: ''
  };

  const reflection = currentPlan.reflection || defaultReflection;

  const updateReflection = (updates: Partial<WeeklyReflection>) => {
    updateWeeklyPlan(selectedWeekId, {
      reflection: { ...reflection, ...updates }
    });
  };

  // Week Logic
  const getWeekDates = (weekId: string) => {
    const [year, week] = weekId.split('-W');
    const d = new Date(parseInt(year), 0, 1);
    const dayOffset = (parseInt(week) - 1) * 7;
    d.setDate(d.getDate() + dayOffset - (d.getDay() || 7) + 1);
    const dates = [];
    for (let i = 0; i < 7; i++) {
      const date = new Date(d);
      date.setDate(d.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = useMemo(() => getWeekDates(selectedWeekId), [selectedWeekId]);
  const dateRangeStr = `${weekDates[0].toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – ${weekDates[6].toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;

  const weekTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDateStr = t.date.split('T')[0];
      return weekDates.some(wd => wd.toISOString().split('T')[0] === taskDateStr);
    });
  }, [tasks, weekDates]);

  const handleWeekChange = (direction: number) => {
    const [year, week] = selectedWeekId.split('-W');
    let nextWeek = parseInt(week) + direction;
    let nextYear = parseInt(year);
    if (nextWeek > 52) { nextWeek = 1; nextYear++; }
    if (nextWeek < 1) { nextWeek = 52; nextYear--; }
    setSelectedWeekId(`${nextYear}-W${nextWeek}`);
  };

  const handleAddTask = (date: Date) => {
    if (newTaskTitle.trim()) {
      addTask(newTaskTitle, newTaskPriority, undefined, date.toISOString(), newTaskArea);
      setNewTaskTitle('');
      setNewTaskPriority(Priority.MEDIUM);
      setNewTaskArea(LifeAreaType.PERSONAL);
      setActiveDayInput(null);
    }
  };

  const toggleTag = (type: 'drained' | 'energized', tag: string) => {
    const list = type === 'drained' ? reflection.drainedBy : reflection.energizedBy;
    const newList = list.includes(tag) ? list.filter(t => t !== tag) : [...list, tag];
    updateReflection(type === 'drained' ? { drainedBy: newList } : { energizedBy: newList });
  };

  const addWin = (winText: string) => {
    if (!winText.trim()) return;
    updateReflection({ wins: [...reflection.wins, winText.trim()] });
  };

  const removeWin = (index: number) => {
    const newWins = reflection.wins.filter((_, i) => i !== index);
    const newBiggest = reflection.biggestWinIndex === index ? -1 : (reflection.biggestWinIndex > index ? reflection.biggestWinIndex - 1 : reflection.biggestWinIndex);
    updateReflection({ wins: newWins, biggestWinIndex: newBiggest });
  };

  return (
    <div className="space-y-12 pb-24 max-w-7xl mx-auto">
      {/* Header Section */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden animate-in fade-in slide-in-from-top-4 duration-500">
        <div className="p-8 flex flex-col md:flex-row items-center justify-between gap-8 bg-gradient-to-br from-white to-slate-50/50">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
              <button onClick={() => handleWeekChange(-1)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ChevronLeft size={20} /></button>
              <div className="text-center min-w-[140px]">
                <h2 className="text-sm font-black text-slate-400 uppercase tracking-widest">{selectedWeekId}</h2>
                <p className="text-lg font-bold text-slate-900">{dateRangeStr}</p>
              </div>
              <button onClick={() => handleWeekChange(1)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ChevronRight size={20} /></button>
            </div>
          </div>

          <div className="flex-1 max-w-md w-full">
            <div className="relative group">
              <Sparkles size={16} className="absolute -top-3 -left-3 text-amber-400 animate-bounce" />
              <input 
                type="text"
                placeholder="What is your primary intent for this week?"
                value={currentPlan.intent}
                onChange={(e) => updateWeeklyPlan(selectedWeekId, { intent: e.target.value })}
                className="w-full bg-transparent text-xl font-bold text-[#1E3A5F] border-b-2 border-slate-100 focus:border-[#6B8E7B] outline-none py-2 px-1 transition-all text-center"
              />
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2 text-center">Current Weekly Intent</p>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-4 bg-white/80 p-4 rounded-2xl border border-slate-100 shadow-sm italic text-slate-500 text-sm max-w-xs relative">
            <Quote size={16} className="absolute -top-2 -left-2 text-slate-200" />
            "Consistency is the foundation of high performance."
          </div>
        </div>
      </div>

      {/* Daily Planner Grid (Existing) */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-7 gap-4 items-start">
        {weekDates.map((date, idx) => {
          const dateStr = date.toISOString().split('T')[0];
          const dayTasks = weekTasks.filter(t => t.date.startsWith(dateStr));
          const isToday = new Date().toISOString().split('T')[0] === dateStr;

          return (
            <div key={idx} className={`bg-white rounded-2xl border ${isToday ? 'border-blue-400 ring-2 ring-blue-50 shadow-lg' : 'border-slate-200'} shadow-sm flex flex-col transition-all overflow-hidden h-fit`}>
              <div className={`p-4 border-b border-slate-100 ${isToday ? 'bg-blue-50/50' : 'bg-slate-50/30'} flex justify-between items-center`}>
                <div>
                  <h4 className={`text-xs font-black uppercase tracking-widest ${isToday ? 'text-blue-600' : 'text-slate-400'}`}>{date.toLocaleDateString('en-US', { weekday: 'short' })}</h4>
                  <p className="text-sm font-bold text-slate-900">{date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</p>
                </div>
                {isToday && <span className="text-[8px] font-black bg-blue-600 text-white px-1.5 py-0.5 rounded-full uppercase">Today</span>}
              </div>

              <div className="p-2 space-y-1">
                {dayTasks.map(task => {
                  const areaInfo = LIFE_AREAS_INFO[task.areaId || LifeAreaType.PERSONAL];
                  return (
                    <div key={task.id} className="group relative">
                      <button 
                        onClick={() => toggleTask(task.id)}
                        className={`w-full text-left p-2 rounded-xl text-xs flex items-start gap-2 transition-all overflow-hidden ${
                          task.completed ? 'bg-slate-50 text-slate-400' : 'hover:bg-slate-50 border border-transparent'
                        }`}
                      >
                        <div className="mt-0.5">
                          {task.completed ? <CheckCircle2 size={12} className="text-green-500" /> : <Circle size={12} className="text-slate-300 group-hover:text-[#6B8E7B]" />}
                        </div>
                        <div className="flex-1 min-w-0 pr-4">
                          <div className="flex items-center gap-1.5">
                            <p className={`font-medium line-clamp-2 ${task.completed ? 'line-through' : 'text-slate-700'}`}>{task.title}</p>
                            {task.isCarriedForward && !task.completed && (
                              <span title="Carried forward from yesterday">
                                <Zap size={10} className="text-amber-500 fill-amber-500" />
                              </span>
                            )}
                          </div>
                          <div className="mt-1 flex flex-wrap items-center gap-1.5">
                            <div className={`text-[8px] font-black uppercase tracking-tighter ${
                              task.priority === Priority.HIGH ? 'text-red-500' : task.priority === Priority.MEDIUM ? 'text-amber-500' : 'text-green-500'
                            }`}>
                              {task.priority}
                            </div>
                            <span className="text-[8px] text-slate-300">•</span>
                            <div className={`text-[8px] font-bold px-1 rounded ${areaInfo.color.split(' ')[0]} ${areaInfo.color.split(' ')[1]}`}>
                              {task.areaId || 'Personal'}
                            </div>
                          </div>
                        </div>
                      </button>
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          deleteTask(task.id);
                        }}
                        className="absolute top-2 right-2 p-1 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all rounded-md hover:bg-red-50"
                        title="Delete task"
                      >
                        <Trash2 size={12} />
                      </button>
                    </div>
                  );
                })}

                {activeDayInput === idx ? (
                  <div className="p-2 animate-in zoom-in-95 duration-200 bg-slate-50 rounded-xl border border-slate-200 mt-2">
                    <input 
                      autoFocus
                      type="text" 
                      placeholder="Task name..."
                      value={newTaskTitle}
                      onChange={(e) => setNewTaskTitle(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleAddTask(date)}
                      className="w-full text-xs p-2 bg-white border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-[#6B8E7B]"
                    />
                    <div className="flex justify-end gap-2 mt-2 pt-2 border-t border-slate-100">
                      <button onClick={() => setActiveDayInput(null)} className="text-[10px] font-bold text-slate-400">Cancel</button>
                      <button onClick={() => handleAddTask(date)} className="text-[10px] font-bold text-blue-600">Add</button>
                    </div>
                  </div>
                ) : (
                  <button 
                    onClick={() => { setActiveDayInput(idx); setNewTaskTitle(''); }}
                    className="w-full p-2 rounded-xl border border-dashed border-slate-200 text-slate-400 hover:text-[#6B8E7B] hover:border-[#6B8E7B] transition-all flex items-center justify-center gap-1 text-[10px] font-bold mt-2"
                  >
                    <Plus size={12} /> ADD
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* ADVANCED WEEKLY REFLECTION SECTION */}
      <section className="bg-white rounded-[40px] border border-slate-200 shadow-2xl shadow-slate-200/50 overflow-hidden">
        <div className="bg-[#1E3A5F] px-12 py-10 text-white flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="flex items-center gap-5">
            <div className="p-4 bg-white/10 rounded-2xl backdrop-blur-xl border border-white/10">
              <Brain size={32} className="text-blue-200" />
            </div>
            <div>
              <h3 className="text-3xl font-black tracking-tight">Weekly Reflection</h3>
              <p className="text-blue-100/60 font-medium text-sm">Deep analysis for continuous growth.</p>
            </div>
          </div>
          <div className="flex items-center gap-2 px-4 py-2 bg-white/5 rounded-full border border-white/5">
            <div className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></div>
            <span className="text-[10px] font-black uppercase tracking-widest text-blue-100/80">Active Review Cycle</span>
          </div>
        </div>

        <div className="p-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

          {/* Column 1: Mood & Energy */}
          <div className="lg:col-span-4 space-y-10">
            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <Smile size={16} className="text-blue-500" /> Current State
              </h4>
              <div className="bg-slate-50 p-6 rounded-[32px] space-y-8 border border-slate-100">
                <div className="flex justify-between items-center gap-2">
                  {MOODS.map((m) => (
                    <button
                      key={m.label}
                      onClick={() => updateReflection({ mood: m.label })}
                      className={`flex flex-col items-center gap-2 p-3 rounded-2xl transition-all ${
                        reflection.mood === m.label ? 'bg-white shadow-lg shadow-slate-200/50 scale-110' : 'hover:bg-white/50 grayscale hover:grayscale-0'
                      }`}
                    >
                      <span className="text-2xl">{m.emoji}</span>
                      <span className={`text-[9px] font-black uppercase ${reflection.mood === m.label ? m.color : 'text-slate-400'}`}>{m.label}</span>
                    </button>
                  ))}
                </div>

                <div className="space-y-4">
                  <div className="flex justify-between items-center">
                    <span className="text-xs font-bold text-slate-500 flex items-center gap-2"><Battery size={14} className="text-green-500" /> Energy Level</span>
                    <span className="text-xs font-black text-slate-900">{reflection.energyLevel}/10</span>
                  </div>
                  <input 
                    type="range" min="1" max="10" 
                    value={reflection.energyLevel}
                    onChange={(e) => updateReflection({ energyLevel: parseInt(e.target.value) })}
                    className="w-full accent-[#6B8E7B] h-1.5 rounded-full bg-slate-200 cursor-pointer"
                  />
                </div>

                <div className="space-y-4">
                  <div className="flex justify-between items-center">
                    <span className="text-xs font-bold text-slate-500 flex items-center gap-2"><CloudLightning size={14} className="text-amber-500" /> Stress Level</span>
                    <span className="text-xs font-black text-slate-900">{reflection.stressLevel}/10</span>
                  </div>
                  <input 
                    type="range" min="1" max="10" 
                    value={reflection.stressLevel}
                    onChange={(e) => updateReflection({ stressLevel: parseInt(e.target.value) })}
                    className="w-full accent-amber-500 h-1.5 rounded-full bg-slate-200 cursor-pointer"
                  />
                </div>
              </div>
            </div>

            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <Star size={16} className="text-amber-500" /> Self-Rating
              </h4>
              <div className="space-y-6 bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                {[
                  { label: 'Productivity', key: 'productivityRating', color: 'accent-blue-500' },
                  { label: 'Happiness', key: 'happinessRating', color: 'accent-rose-500' },
                  { label: 'Life Balance', key: 'balanceRating', color: 'accent-[#6B8E7B]' }
                ].map((rating) => (
                  <div key={rating.key} className="space-y-3">
                    <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-slate-500">
                      <span>{rating.label}</span>
                      <span className="text-slate-900">{(reflection as any)[rating.key]}/10</span>
                    </div>
                    <input 
                      type="range" min="1" max="10" 
                      value={(reflection as any)[rating.key]}
                      onChange={(e) => updateReflection({ [rating.key]: parseInt(e.target.value) })}
                      className={`w-full ${rating.color} h-1 bg-slate-200 rounded-full cursor-pointer`}
                    />
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Column 2: Wins & Growth */}
          <div className="lg:col-span-5 space-y-10">
            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <Trophy size={16} className="text-amber-500" /> Wins of the Week
              </h4>
              <div className="space-y-3">
                {reflection.wins.map((win, i) => (
                  <div key={i} className={`flex items-center gap-3 p-4 rounded-2xl border transition-all group ${
                    reflection.biggestWinIndex === i ? 'bg-amber-50 border-amber-200 ring-2 ring-amber-100 shadow-sm' : 'bg-white border-slate-100'
                  }`}>
                    <button 
                      onClick={() => updateReflection({ biggestWinIndex: reflection.biggestWinIndex === i ? -1 : i })}
                      className={`p-2 rounded-xl transition-all ${reflection.biggestWinIndex === i ? 'bg-amber-400 text-white' : 'bg-slate-50 text-slate-300 hover:text-amber-400'}`}
                      title="Mark as biggest win"
                    >
                      <Star size={14} className={reflection.biggestWinIndex === i ? 'fill-white' : ''} />
                    </button>
                    <p className={`flex-1 text-sm font-semibold ${reflection.biggestWinIndex === i ? 'text-amber-900' : 'text-slate-700'}`}>{win}</p>
                    <button onClick={() => removeWin(i)} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                {reflection.wins.length < 5 && (
                  <div className="relative">
                    <input 
                      type="text"
                      placeholder="Capture a win..."
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                          addWin(e.currentTarget.value);
                          e.currentTarget.value = '';
                        }
                      }}
                      className="w-full bg-slate-50 border border-dashed border-slate-200 rounded-2xl p-4 text-sm font-medium outline-none focus:border-[#6B8E7B] focus:bg-white transition-all pr-12"
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-slate-300 uppercase tracking-tighter">Enter to Save</div>
                  </div>
                )}
              </div>
            </div>

            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                <Sun size={16} className="text-[#6B8E7B]" /> Energy Audit
              </h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-rose-50/30 p-6 rounded-[32px] border border-rose-100 space-y-4">
                  <h5 className="text-[10px] font-black text-rose-500 uppercase tracking-widest flex items-center gap-2"><CloudLightning size={12} /> Drains</h5>
                  <div className="flex flex-wrap gap-2">
                    {DRAIN_TAGS.map(tag => (
                      <button 
                        key={tag}
                        onClick={() => toggleTag('drained', tag)}
                        className={`text-[10px] font-bold px-3 py-1.5 rounded-full transition-all border ${
                          reflection.drainedBy.includes(tag) ? 'bg-rose-500 text-white border-rose-500 shadow-md' : 'bg-white text-rose-400 border-rose-100 hover:border-rose-300'
                        }`}
                      >
                        {tag}
                      </button>
                    ))}
                  </div>
                  <input 
                    type="text" 
                    placeholder="+ Add custom"
                    value={customDrain}
                    onChange={e => setCustomDrain(e.target.value)}
                    onKeyDown={e => {
                      if (e.key === 'Enter' && customDrain.trim()) {
                        toggleTag('drained', customDrain.trim());
                        setCustomDrain('');
                      }
                    }}
                    className="w-full bg-transparent border-b border-rose-100 text-[10px] font-bold px-1 py-1 focus:border-rose-400 outline-none text-rose-900"
                  />
                </div>

                <div className="bg-green-50/30 p-6 rounded-[32px] border border-green-100 space-y-4">
                  <h5 className="text-[10px] font-black text-[#6B8E7B] uppercase tracking-widest flex items-center gap-2"><Coffee size={12} /> Boosters</h5>
                  <div className="flex flex-wrap gap-2">
                    {ENERGY_TAGS.map(tag => (
                      <button 
                        key={tag}
                        onClick={() => toggleTag('energized', tag)}
