};

export default Planner;

import { useState, useEffect, useCallback } from 'react';
import { Goal, Task, Habit, Decision, WeeklyPlan, User, View, Priority, SubGoal, WeeklyReflection, LifeAreaType } from '../types';
import { MOCK_USER, MOCK_GOALS, MOCK_TASKS, MOCK_HABITS, MOCK_DECISIONS } from '../mockData';

const STORAGE_KEY = 'lifeos_data_v1_planner';

interface AppState {
  user: User;
  goals: Goal[];
  tasks: Task[];
  habits: Habit[];
  decisions: Decision[];
  weeklyPlans: { [weekId: string]: WeeklyPlan };
  currentView: View;
  selectedWeekId: string;
}

const getWeekId = (date: Date) => {
  const d = new Date(date);
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + 4 - (d.getDay() || 7));
  const yearStart = new Date(d.getFullYear(), 0, 1);
  const weekNo = Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
  return `${d.getFullYear()}-W${weekNo}`;
};

export function useLifeOS() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    const initial = saved ? JSON.parse(saved) : INITIAL_STATE;
    // Basic migration to ensure weeklyPlans exist
    if (!initial.weeklyPlans) initial.weeklyPlans = {};
    return { ...initial, selectedWeekId: getWeekId(new Date()) };
  });

  const [highlightedId, setHighlightedId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const carryForwardTasks = useCallback(() => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayStr = today.toISOString().split('T')[0];

    setState(prev => {
      let changed = false;
      const updatedTasks = prev.tasks.map(task => {
        const taskDate = new Date(task.date);
        taskDate.setHours(0, 0, 0, 0);
        if (!task.completed && taskDate.getTime() < today.getTime()) {
          changed = true;
          const timePart = task.date.includes('T') ? task.date.split('T')[1] : '09:00:00.000Z';
          return {
            ...task,
            date: `${todayStr}T${timePart}`,
            isCarriedForward: true
          };
        }
        return task;
      });
      if (!changed) return prev;
      return { ...prev, tasks: updatedTasks };
    });
  }, []);

  useEffect(() => {
    carryForwardTasks();
    const interval = setInterval(carryForwardTasks, 60000);
    return () => clearInterval(interval);
  }, [state.currentView, carryForwardTasks]);

  const setView = (view: View) => setState(prev => ({ ...prev, currentView: view }));
  const setSelectedWeekId = (id: string) => setState(prev => ({ ...prev, selectedWeekId: id }));

  const triggerHighlight = (id: string, view?: View) => {
    if (view) setView(view);
    setHighlightedId(id);
    setTimeout(() => setHighlightedId(null), 3000);
  };

  const toggleTask = (taskId: string) => {
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.map(t => t.id === taskId ? { ...t, completed: !t.completed } : t)
    }));
  };

  const deleteTask = (taskId: string) => {
    setState(prev => ({
      ...prev,
      tasks: prev.tasks.filter(t => t.id !== taskId)
    }));
  };

  const addTask = (title: string, priority: Priority = Priority.MEDIUM, goalId?: string, date?: string, areaId?: LifeAreaType) => {
    const newTask: Task = {
      id: `t-${Date.now()}`,
      title,
      goalId,
      areaId: areaId || LifeAreaType.PERSONAL,
      completed: false,
      date: date || new Date().toISOString(),
      estimatedHours: 1,
      priority
    };
    setState(prev => ({ ...prev, tasks: [newTask, ...prev.tasks] }));
  };

  const updateWeeklyPlan = (weekId: string, updates: Partial<WeeklyPlan>) => {
    setState(prev => {
      const existing = prev.weeklyPlans[weekId] || { 
        weekId, 
        intent: '', 
        focus: '', 
        priorities: [], 
        allocatedHours: 40 
      };
      return {
        ...prev,
        weeklyPlans: {
          ...prev.weeklyPlans,
          [weekId]: { ...existing, ...updates }
        }
      };
    });
  };

  const toggleHabit = (habitId: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === habitId ? { ...h, completedToday: !h.completedToday, streak: h.completedToday ? h.streak - 1 : h.streak + 1 } : h)
    }));
  };

  const addGoal = (goal: Goal) => setState(prev => ({ ...prev, goals: [...prev.goals, goal] }));
  const updateGoal = (id: string, updates: Partial<Goal>) => {
    setState(prev => ({
      ...prev,
      goals: prev.goals.map(g => g.id === id ? { ...g, ...updates } : g)
    }));
  };

  const addSubGoal = (goalId: string, title: string) => {
    setState(prev => ({
      ...prev,
      goals: prev.goals.map(g => {
        if (g.id !== goalId) return g;
        const newSubGoal: SubGoal = { id: `sg-${Date.now()}`, title, completed: false };
        const updatedSubGoals = [...g.subGoals, newSubGoal];
        const progress = Math.round((updatedSubGoals.filter(sg => sg.completed).length / updatedSubGoals.length) * 100);
        return { ...g, subGoals: updatedSubGoals, progress };
      })
    }));
  };

  const toggleSubGoal = (goalId: string, subGoalId: string) => {
    setState(prev => ({
      ...prev,
      goals: prev.goals.map(g => {
        if (g.id !== goalId) return g;
        const updatedSubGoals = g.subGoals.map(sg => sg.id === subGoalId ? { ...sg, completed: !sg.completed } : sg);
        const progress = updatedSubGoals.length > 0 ? Math.round((updatedSubGoals.filter(sg => sg.completed).length / updatedSubGoals.length) * 100) : 0;
        return { ...g, subGoals: updatedSubGoals, progress };
      })
    }));
  };

  const addDecision = (decision: Decision) => setState(prev => ({ ...prev, decisions: [decision, ...prev.decisions] }));

  const getGoalRisk = (goal: Goal) => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const target = new Date(goal.targetDate);
    const diffDays = Math.ceil((target.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
    if (diffDays < 0 && goal.progress < 100) return 'OVERDUE';
    if (goal.progress < 50 && diffDays < 90) return 'HIGH';
    if (goal.progress < 75 && diffDays < 30) return 'MEDIUM';
    return 'LOW';
  };

  const getWeeklyLoadStatus = () => {
    const today = new Date().toISOString().split('T')[0];
    const todaysTasks = state.tasks.filter(t => t.date.startsWith(today));
    const totalHoursToday = todaysTasks.reduce((sum, t) => sum + t.estimatedHours, 0);
    const weeklyPlan = state.weeklyPlans[state.selectedWeekId];
    const dailyLimit = (weeklyPlan?.allocatedHours || 35) / 7;
    return { totalHours: totalHoursToday, limit: dailyLimit, isOverloaded: totalHoursToday > dailyLimit };
  };

  const calculateDecisionScores = (decision: Decision) => {
    return decision.options.map(opt => {
      let total = 0;
      decision.criteria.forEach(crit => { total += (opt.scores[crit.id] || 0) * crit.weight; });
      return { ...opt, totalScore: total };
    }).sort((a, b) => b.totalScore - a.totalScore);
  };

  return {
    ...state, highlightedId, setView, setSelectedWeekId, updateWeeklyPlan, triggerHighlight,
    toggleTask, deleteTask, addTask, toggleHabit, addGoal, updateGoal, addSubGoal, toggleSubGoal,
    addDecision, getGoalRisk, getWeeklyLoadStatus, calculateDecisionScores
  };
}

const INITIAL_STATE: AppState = {
  user: MOCK_USER,
  goals: MOCK_GOALS,
  tasks: MOCK_TASKS,
  habits: MOCK_HABITS,
  decisions: MOCK_DECISIONS,
  weeklyPlans: {},
  currentView: 'dashboard',
  selectedWeekId: getWeekId(new Date()),
};

import React, { useState, useMemo } from 'react';
import { WeeklyPlan, LifeAreaType, Priority, Task, Goal, WeeklyReflection } from '../types';
import { LIFE_AREAS_INFO } from '../constants';
import { 
  ChevronLeft, ChevronRight, Sparkles, Plus, CheckCircle2, Circle, AlertCircle, Quote, Smile, Frown, Meh, Heart,
  Brain, Zap, Trash2, Battery, CloudLightning, Sun, PenLine, Star, Trophy, Coffee, X
} from 'lucide-react';

interface PlannerProps {
  selectedWeekId: string;
  weeklyPlans: { [weekId: string]: WeeklyPlan };
  tasks: Task[];
  goals: Goal[];
  setSelectedWeekId: (id: string) => void;
  updateWeeklyPlan: (weekId: string, updates: Partial<WeeklyPlan>) => void;
  addTask: (title: string, priority: Priority, goalId?: string, date?: string, areaId?: LifeAreaType) => void;
  toggleTask: (id: string) => void;
  deleteTask: (id: string) => void;
}

const Planner: React.FC<PlannerProps> = ({ 
  selectedWeekId, weeklyPlans, tasks, goals, setSelectedWeekId, updateWeeklyPlan, addTask, toggleTask, deleteTask
}) => {
  const currentPlan = weeklyPlans[selectedWeekId] || { weekId: selectedWeekId, intent: '', focus: '', priorities: [], allocatedHours: 40 };

  const [activeDayInput, setActiveDayInput] = useState<number | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>(Priority.MEDIUM);
  const [newTaskArea, setNewTaskArea] = useState<LifeAreaType>(LifeAreaType.PERSONAL);

  const [customDrain, setCustomDrain] = useState('');
  const [customEnergizer, setCustomEnergizer] = useState('');

  const MOODS = [
    { label: 'Happy', emoji: '😊', color: 'text-green-500' },
    { label: 'Calm', emoji: '😌', color: 'text-blue-400' },
    { label: 'Neutral', emoji: '😐', color: 'text-slate-400' },
    { label: 'Stressed', emoji: '😫', color: 'text-amber-500' },
    { label: 'Sad', emoji: '😢', color: 'text-indigo-600' }
  ];

  const DRAIN_TAGS = ['Overplanning', 'Social Media', 'Poor Sleep', 'Distractions', 'Toxic Conversation', 'Health Issues'];
  const ENERGY_TAGS = ['Workout', 'Deep Work', 'Family Time', 'Learning', 'Friends', 'Self-care'];

  // Robustly handle missing properties in reflection (migration safety)
  const reflection: WeeklyReflection = useMemo(() => {
    const r = currentPlan.reflection || {};
    return {
      mood: r.mood || 'Neutral',
      energyLevel: r.energyLevel ?? 5,
      stressLevel: r.stressLevel ?? 3,
      wins: r.wins || [],
      biggestWinIndex: r.biggestWinIndex ?? -1,
      drainedBy: r.drainedBy || [],
      energizedBy: r.energizedBy || [],
      lessonLearned: r.lessonLearned || '',
      productivityRating: r.productivityRating ?? 5,
      happinessRating: r.happinessRating ?? 5,
      balanceRating: r.balanceRating ?? 5,
      improvementFocus: r.improvementFocus || '',
      noteToSelf: r.noteToSelf || ''
    };
  }, [currentPlan.reflection]);

  const updateReflection = (updates: Partial<WeeklyReflection>) => {
    updateWeeklyPlan(selectedWeekId, {
      reflection: { ...reflection, ...updates }
    });
  };

  const getWeekDates = (weekId: string) => {
    const [year, week] = weekId.split('-W');
    const d = new Date(parseInt(year), 0, 1);
    const dayOffset = (parseInt(week) - 1) * 7;
    d.setDate(d.getDate() + dayOffset - (d.getDay() || 7) + 1);
    const dates = [];
    for (let i = 0; i < 7; i++) {
      const date = new Date(d);
      date.setDate(d.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = useMemo(() => getWeekDates(selectedWeekId), [selectedWeekId]);
  const dateRangeStr = `${weekDates[0].toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – ${weekDates[6].toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;

  const weekTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDateStr = t.date.split('T')[0];
      return weekDates.some(wd => wd.toISOString().split('T')[0] === taskDateStr);
    });
  }, [tasks, weekDates]);

  const handleWeekChange = (direction: number) => {
    const [year, week] = selectedWeekId.split('-W');
    let nextWeek = parseInt(week) + direction;
    let nextYear = parseInt(year);
    if (nextWeek > 52) { nextWeek = 1; nextYear++; }
    if (nextWeek < 1) { nextWeek = 52; nextYear--; }
    setSelectedWeekId(`${nextYear}-W${nextWeek}`);
  };

  const handleAddTask = (date: Date) => {
    if (newTaskTitle.trim()) {
      addTask(newTaskTitle, newTaskPriority, undefined, date.toISOString(), newTaskArea);
      setNewTaskTitle('');
      setNewTaskPriority(Priority.MEDIUM);
      setNewTaskArea(LifeAreaType.PERSONAL);
      setActiveDayInput(null);
    }
  };

  const toggleTag = (type: 'drained' | 'energized', tag: string) => {
    const list = type === 'drained' ? reflection.drainedBy : reflection.energizedBy;
    const newList = list.includes(tag) ? list.filter(t => t !== tag) : [...list, tag];
    updateReflection(type === 'drained' ? { drainedBy: newList } : { energizedBy: newList });
  };

  const addWin = (winText: string) => {
    if (!winText.trim()) return;
    updateReflection({ wins: [...reflection.wins, winText.trim()] });
  };

  const removeWin = (index: number) => {
    const newWins = reflection.wins.filter((_, i) => i !== index);
    const newBiggest = reflection.biggestWinIndex === index ? -1 : (reflection.biggestWinIndex > index ? reflection.biggestWinIndex - 1 : reflection.biggestWinIndex);
    updateReflection({ wins: newWins, biggestWinIndex: newBiggest });
  };

  return (
    <div className="space-y-12 pb-24 max-w-7xl mx-auto animate-in fade-in duration-700">
      {/* Header Section */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-8 flex flex-col md:flex-row items-center justify-between gap-8 bg-gradient-to-br from-white to-slate-50/50">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
              <button onClick={() => handleWeekChange(-1)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ChevronLeft size={20} /></button>
              <div className="text-center min-w-[140px]">
                <h2 className="text-sm font-black text-slate-400 uppercase tracking-widest">{selectedWeekId}</h2>
                <p className="text-lg font-bold text-slate-900">{dateRangeStr}</p>
              </div>
              <button onClick={() => handleWeekChange(1)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ChevronRight size={20} /></button>
            </div>
          </div>
          <div className="flex-1 max-w-md w-full">
            <div className="relative group">
              <Sparkles size={16} className="absolute -top-3 -left-3 text-amber-400 animate-bounce" />
              <input 
                type="text" placeholder="What is your primary intent for this week?"
                value={currentPlan.intent}
                onChange={(e) => updateWeeklyPlan(selectedWeekId, { intent: e.target.value })}
                className="w-full bg-transparent text-xl font-bold text-[#1E3A5F] border-b-2 border-slate-100 focus:border-[#6B8E7B] outline-none py-2 px-1 transition-all text-center"
              />
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2 text-center">Current Weekly Intent</p>
            </div>
          </div>
          <div className="hidden lg:flex items-center gap-4 bg-white/80 p-4 rounded-2xl border border-slate-100 shadow-sm italic text-slate-500 text-sm max-w-xs relative">
            <Quote size={16} className="absolute -top-2 -left-2 text-slate-200" />
            "Consistency is the foundation of high performance."
          </div>
        </div>
      </div>

      {/* Daily Planner Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-7 gap-4 items-start">
        {weekDates.map((date, idx) => {
          const dateStr = date.toISOString().split('T')[0];
          const dayTasks = weekTasks.filter(t => t.date.startsWith(dateStr));
          const isToday = new Date().toISOString().split('T')[0] === dateStr;
          return (
            <div key={idx} className={`bg-white rounded-2xl border ${isToday ? 'border-blue-400 ring-2 ring-blue-50 shadow-lg' : 'border-slate-200'} shadow-sm flex flex-col transition-all h-fit overflow-hidden`}>
              <div className={`p-4 border-b border-slate-100 ${isToday ? 'bg-blue-50/50' : 'bg-slate-50/30'} flex justify-between items-center`}>
                <div>
                  <h4 className={`text-xs font-black uppercase tracking-widest ${isToday ? 'text-blue-600' : 'text-slate-400'}`}>{date.toLocaleDateString('en-US', { weekday: 'short' })}</h4>
                  <p className="text-sm font-bold text-slate-900">{date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</p>
                </div>
                {isToday && <span className="text-[8px] font-black bg-blue-600 text-white px-1.5 py-0.5 rounded-full uppercase">Today</span>}
              </div>
              <div className="p-2 space-y-1">
                {dayTasks.map(task => {
                  const areaInfo = LIFE_AREAS_INFO[task.areaId || LifeAreaType.PERSONAL];
                  return (
                    <div key={task.id} className="group relative">
                      <button onClick={() => toggleTask(task.id)} className={`w-full text-left p-2 rounded-xl text-xs flex items-start gap-2 transition-all ${task.completed ? 'bg-slate-50 text-slate-400' : 'hover:bg-slate-50 border border-transparent'}`}>
