                  ))}
                </div>
                <div className="space-y-4">
                  <div className="flex justify-between items-center text-xs font-bold text-slate-500"><span>Energy Level</span><span>{reflection.energyLevel}/10</span></div>
                  <input type="range" min="1" max="10" value={reflection.energyLevel} onChange={e => updateReflection({ energyLevel: parseInt(e.target.value) })} className="w-full accent-[#6B8E7B] h-1.5 rounded-full bg-slate-200" />
                </div>
                <div className="space-y-4">
                  <div className="flex justify-between items-center text-xs font-bold text-slate-500"><span>Stress Level</span><span>{reflection.stressLevel}/10</span></div>
                  <input type="range" min="1" max="10" value={reflection.stressLevel} onChange={e => updateReflection({ stressLevel: parseInt(e.target.value) })} className="w-full accent-amber-500 h-1.5 rounded-full bg-slate-200" />
                </div>
              </div>
            </div>
            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Star size={16} /> Self-Rating</h4>
              <div className="space-y-6 bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                {[{ label: 'Productivity', key: 'productivityRating', color: 'accent-blue-500' }, { label: 'Happiness', key: 'happinessRating', color: 'accent-rose-500' }, { label: 'Balance', key: 'balanceRating', color: 'accent-[#6B8E7B]' }].map(rating => (
                  <div key={rating.key} className="space-y-3">
                    <div className="flex justify-between items-center text-[10px] font-black uppercase text-slate-500"><span>{rating.label}</span><span>{(reflection as any)[rating.key]}/10</span></div>
                    <input type="range" min="1" max="10" value={(reflection as any)[rating.key]} onChange={e => updateReflection({ [rating.key]: parseInt(e.target.value) })} className={`w-full ${rating.color} h-1 rounded-full`} />
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Col 2: Wins */}
          <div className="lg:col-span-5 space-y-10">
            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Trophy size={16} /> Wins of the Week</h4>
              <div className="space-y-3">
                {reflection.wins.map((win, i) => (
                  <div key={i} className={`flex items-center gap-3 p-4 rounded-2xl border transition-all ${reflection.biggestWinIndex === i ? 'bg-amber-50 border-amber-200 ring-2 ring-amber-100' : 'bg-white border-slate-100 group'}`}>
                    <button onClick={() => updateReflection({ biggestWinIndex: reflection.biggestWinIndex === i ? -1 : i })} className={`p-2 rounded-xl transition-all ${reflection.biggestWinIndex === i ? 'bg-amber-400 text-white' : 'bg-slate-50 text-slate-300 hover:text-amber-400'}`}><Star size={14} fill={reflection.biggestWinIndex === i ? 'white' : 'none'} /></button>
                    <p className={`flex-1 text-sm font-semibold ${reflection.biggestWinIndex === i ? 'text-amber-900' : 'text-slate-700'}`}>{win}</p>
                    <button onClick={() => removeWin(i)} className="p-2 text-slate-300 hover:text-red-500"><Trash2 size={14} /></button>
                  </div>
                ))}
                {reflection.wins.length < 5 && (
                  <div className="relative">
                    <input type="text" placeholder="Capture a win..." onKeyDown={e => { if (e.key === 'Enter') { addWin(e.currentTarget.value); e.currentTarget.value = ''; } }} className="w-full bg-slate-50 border border-dashed border-slate-200 rounded-2xl p-4 text-sm font-medium outline-none pr-12" />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 text-[10px] font-black text-slate-300">Enter</div>
                  </div>
                )}
              </div>
            </div>
            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Sun size={16} /> Energy Audit</h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-rose-50/30 p-6 rounded-[32px] border border-rose-100 space-y-4">
                  <h5 className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Drains</h5>
                  <div className="flex flex-wrap gap-2">
                    {DRAIN_TAGS.map(tag => (
                      <button key={tag} onClick={() => toggleTag('drained', tag)} className={`text-[10px] font-bold px-3 py-1.5 rounded-full border ${reflection.drainedBy.includes(tag) ? 'bg-rose-500 text-white' : 'bg-white text-rose-400'}`}>{tag}</button>
                    ))}
                  </div>
                </div>
                <div className="bg-green-50/30 p-6 rounded-[32px] border border-green-100 space-y-4">
                  <h5 className="text-[10px] font-black text-[#6B8E7B] uppercase tracking-widest">Boosters</h5>
                  <div className="flex flex-wrap gap-2">
                    {ENERGY_TAGS.map(tag => (
                      <button key={tag} onClick={() => toggleTag('energized', tag)} className={`text-[10px] font-bold px-3 py-1.5 rounded-full border ${reflection.energizedBy.includes(tag) ? 'bg-[#6B8E7B] text-white' : 'bg-white text-[#6B8E7B]'}`}>{tag}</button>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Col 3: Focus */}
          <div className="lg:col-span-3 space-y-8">
            <div className="space-y-4">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><PenLine size={16} /> Lesson Learned</h4>
              <textarea placeholder="What was your biggest insight?" value={reflection.lessonLearned} onChange={e => updateReflection({ lessonLearned: e.target.value.slice(0, 300) })} className="w-full bg-slate-50 border border-slate-200 rounded-3xl p-5 text-sm font-medium outline-none min-h-[140px] resize-none" />
            </div>
            <div className="space-y-4">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Zap size={16} /> Next Week Focus</h4>
              <input placeholder="One area to improve..." value={reflection.improvementFocus} onChange={e => updateReflection({ improvementFocus: e.target.value })} className="w-full bg-amber-50/50 border border-amber-100 rounded-2xl p-4 text-sm font-bold text-amber-900 outline-none" />
            </div>
            <div className="space-y-4">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Heart size={16} /> Message to Future Self</h4>
              <textarea placeholder="Encouragement or truth..." value={reflection.noteToSelf} onChange={e => updateReflection({ noteToSelf: e.target.value })} className="w-full bg-rose-50/20 border border-rose-100 rounded-3xl p-5 text-sm font-medium italic outline-none min-h-[120px] resize-none" />
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Planner;

import React, { useState, useMemo } from 'react';
import { WeeklyPlan, LifeAreaType, Priority, Task, Goal, WeeklyReflection } from '../types';
import { LIFE_AREAS_INFO } from '../constants';
import { 
  ChevronLeft, ChevronRight, Sparkles, Plus, CheckCircle2, Circle, AlertCircle, Quote, Smile, Frown, Meh, Heart,
  Brain, Zap, Trash2, Battery, CloudLightning, Sun, PenLine, Star, Trophy, Coffee, X
} from 'lucide-react';

interface PlannerProps {
  selectedWeekId: string;
  weeklyPlans: { [weekId: string]: WeeklyPlan };
  tasks: Task[];
  goals: Goal[];
  setSelectedWeekId: (id: string) => void;
  updateWeeklyPlan: (weekId: string, updates: Partial<WeeklyPlan>) => void;
  addTask: (title: string, priority: Priority, goalId?: string, date?: string, areaId?: LifeAreaType) => void;
  toggleTask: (id: string) => void;
  deleteTask: (id: string) => void;
}

const Planner: React.FC<PlannerProps> = ({ 
  selectedWeekId, weeklyPlans, tasks, goals, setSelectedWeekId, updateWeeklyPlan, addTask, toggleTask, deleteTask
}) => {
  const currentPlan = weeklyPlans[selectedWeekId] || { weekId: selectedWeekId, intent: '', focus: '', priorities: [], allocatedHours: 40 };

  const [activeDayInput, setActiveDayInput] = useState<number | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Priority>(Priority.MEDIUM);
  const [newTaskArea, setNewTaskArea] = useState<LifeAreaType>(LifeAreaType.PERSONAL);

  const [customDrain, setCustomDrain] = useState('');
  const [customEnergizer, setCustomEnergizer] = useState('');

  const MOODS = [
    { label: 'Happy', emoji: '😊', color: 'text-green-500' },
    { label: 'Calm', emoji: '😌', color: 'text-blue-400' },
    { label: 'Neutral', emoji: '😐', color: 'text-slate-400' },
    { label: 'Stressed', emoji: '😫', color: 'text-amber-500' },
    { label: 'Sad', emoji: '😢', color: 'text-indigo-600' }
  ];

  const DRAIN_TAGS = ['Overplanning', 'Social Media', 'Poor Sleep', 'Distractions', 'Toxic Conversation', 'Health Issues'];
  const ENERGY_TAGS = ['Workout', 'Deep Work', 'Family Time', 'Learning', 'Friends', 'Self-care'];

  // Robustly handle missing properties in reflection (migration safety)
  // Fix: Cast the fallback empty object to Partial<WeeklyReflection> to avoid "Property does not exist on type '{}'" errors
  const reflection: WeeklyReflection = useMemo(() => {
    const r = currentPlan.reflection || ({} as Partial<WeeklyReflection>);
    return {
      mood: r.mood || 'Neutral',
      energyLevel: r.energyLevel ?? 5,
      stressLevel: r.stressLevel ?? 3,
      wins: r.wins || [],
      biggestWinIndex: r.biggestWinIndex ?? -1,
      drainedBy: r.drainedBy || [],
      energizedBy: r.energizedBy || [],
      lessonLearned: r.lessonLearned || '',
      productivityRating: r.productivityRating ?? 5,
      happinessRating: r.happinessRating ?? 5,
      balanceRating: r.balanceRating ?? 5,
      improvementFocus: r.improvementFocus || '',
      noteToSelf: r.noteToSelf || ''
    };
  }, [currentPlan.reflection]);

  const updateReflection = (updates: Partial<WeeklyReflection>) => {
    updateWeeklyPlan(selectedWeekId, {
      reflection: { ...reflection, ...updates }
    });
  };

  const getWeekDates = (weekId: string) => {
    const [year, week] = weekId.split('-W');
    const d = new Date(parseInt(year), 0, 1);
    const dayOffset = (parseInt(week) - 1) * 7;
    d.setDate(d.getDate() + dayOffset - (d.getDay() || 7) + 1);
    const dates = [];
    for (let i = 0; i < 7; i++) {
      const date = new Date(d);
      date.setDate(d.getDate() + i);
      dates.push(date);
    }
    return dates;
  };

  const weekDates = useMemo(() => getWeekDates(selectedWeekId), [selectedWeekId]);
  const dateRangeStr = `${weekDates[0].toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – ${weekDates[6].toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;

  const weekTasks = useMemo(() => {
    return tasks.filter(t => {
      const taskDateStr = t.date.split('T')[0];
      return weekDates.some(wd => wd.toISOString().split('T')[0] === taskDateStr);
    });
  }, [tasks, weekDates]);

  const handleWeekChange = (direction: number) => {
    const [year, week] = selectedWeekId.split('-W');
    let nextWeek = parseInt(week) + direction;
    let nextYear = parseInt(year);
    if (nextWeek > 52) { nextWeek = 1; nextYear++; }
    if (nextWeek < 1) { nextWeek = 52; nextYear--; }
    setSelectedWeekId(`${nextYear}-W${nextWeek}`);
  };

  const handleAddTask = (date: Date) => {
    if (newTaskTitle.trim()) {
      addTask(newTaskTitle, newTaskPriority, undefined, date.toISOString(), newTaskArea);
      setNewTaskTitle('');
      setNewTaskPriority(Priority.MEDIUM);
      setNewTaskArea(LifeAreaType.PERSONAL);
      setActiveDayInput(null);
    }
  };

  const toggleTag = (type: 'drained' | 'energized', tag: string) => {
    const list = type === 'drained' ? reflection.drainedBy : reflection.energizedBy;
    const newList = list.includes(tag) ? list.filter(t => t !== tag) : [...list, tag];
    updateReflection(type === 'drained' ? { drainedBy: newList } : { energizedBy: newList });
  };

  const addWin = (winText: string) => {
    if (!winText.trim()) return;
    updateReflection({ wins: [...reflection.wins, winText.trim()] });
  };

  const removeWin = (index: number) => {
    const newWins = reflection.wins.filter((_, i) => i !== index);
    const newBiggest = reflection.biggestWinIndex === index ? -1 : (reflection.biggestWinIndex > index ? reflection.biggestWinIndex - 1 : reflection.biggestWinIndex);
    updateReflection({ wins: newWins, biggestWinIndex: newBiggest });
  };

  return (
    <div className="space-y-12 pb-24 max-w-7xl mx-auto animate-in fade-in duration-700">
      {/* Header Section */}
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="p-8 flex flex-col md:flex-row items-center justify-between gap-8 bg-gradient-to-br from-white to-slate-50/50">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
              <button onClick={() => handleWeekChange(-1)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ChevronLeft size={20} /></button>
              <div className="text-center min-w-[140px]">
                <h2 className="text-sm font-black text-slate-400 uppercase tracking-widest">{selectedWeekId}</h2>
                <p className="text-lg font-bold text-slate-900">{dateRangeStr}</p>
              </div>
              <button onClick={() => handleWeekChange(1)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><ChevronRight size={20} /></button>
            </div>
          </div>
          <div className="flex-1 max-w-md w-full">
            <div className="relative group">
              <Sparkles size={16} className="absolute -top-3 -left-3 text-amber-400 animate-bounce" />
              <input 
                type="text" placeholder="What is your primary intent for this week?"
                value={currentPlan.intent}
                onChange={(e) => updateWeeklyPlan(selectedWeekId, { intent: e.target.value })}
                className="w-full bg-transparent text-xl font-bold text-[#1E3A5F] border-b-2 border-slate-100 focus:border-[#6B8E7B] outline-none py-2 px-1 transition-all text-center"
              />
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2 text-center">Current Weekly Intent</p>
            </div>
          </div>
          <div className="hidden lg:flex items-center gap-4 bg-white/80 p-4 rounded-2xl border border-slate-100 shadow-sm italic text-slate-500 text-sm max-w-xs relative">
            <Quote size={16} className="absolute -top-2 -left-2 text-slate-200" />
            "Consistency is the foundation of high performance."
          </div>
        </div>
      </div>

      {/* Daily Planner Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-7 gap-4 items-start">
        {weekDates.map((date, idx) => {
          const dateStr = date.toISOString().split('T')[0];
          const dayTasks = weekTasks.filter(t => t.date.startsWith(dateStr));
          const isToday = new Date().toISOString().split('T')[0] === dateStr;
          return (
            <div key={idx} className={`bg-white rounded-2xl border ${isToday ? 'border-blue-400 ring-2 ring-blue-50 shadow-lg' : 'border-slate-200'} shadow-sm flex flex-col transition-all h-fit overflow-hidden`}>
              <div className={`p-4 border-b border-slate-100 ${isToday ? 'bg-blue-50/50' : 'bg-slate-50/30'} flex justify-between items-center`}>
                <div>
                  <h4 className={`text-xs font-black uppercase tracking-widest ${isToday ? 'text-blue-600' : 'text-slate-400'}`}>{date.toLocaleDateString('en-US', { weekday: 'short' })}</h4>
                  <p className="text-sm font-bold text-slate-900">{date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</p>
                </div>
                {isToday && <span className="text-[8px] font-black bg-blue-600 text-white px-1.5 py-0.5 rounded-full uppercase">Today</span>}
              </div>
              <div className="p-2 space-y-1">
                {dayTasks.map(task => {
                  const areaInfo = LIFE_AREAS_INFO[task.areaId || LifeAreaType.PERSONAL];
                  return (
                    <div key={task.id} className="group relative">
                      <button onClick={() => toggleTask(task.id)} className={`w-full text-left p-2 rounded-xl text-xs flex items-start gap-2 transition-all ${task.completed ? 'bg-slate-50 text-slate-400' : 'hover:bg-slate-50 border border-transparent'}`}>
                        <div className="mt-0.5">{task.completed ? <CheckCircle2 size={12} className="text-green-500" /> : <Circle size={12} className="text-slate-300" />}</div>
                        <div className="flex-1 min-w-0 pr-4">
                          <p className={`font-medium line-clamp-2 ${task.completed ? 'line-through' : 'text-slate-700'}`}>{task.title}</p>
                          <div className="mt-1 flex flex-wrap items-center gap-1.5 text-[8px] font-black uppercase">
                            <span className={task.priority === Priority.HIGH ? 'text-red-500' : task.priority === Priority.MEDIUM ? 'text-amber-500' : 'text-green-500'}>{task.priority}</span>
                            <span className="text-slate-300">•</span>
                            <span className={`px-1 rounded ${areaInfo.color.split(' ')[0]} ${areaInfo.color.split(' ')[1]}`}>{task.areaId || 'Personal'}</span>
                          </div>
                        </div>
                      </button>
                      <button onClick={(e) => { e.stopPropagation(); deleteTask(task.id); }} className="absolute top-2 right-2 p-1 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all rounded-md hover:bg-red-50">
                        <Trash2 size={12} />
                      </button>
                    </div>
                  );
                })}
                {activeDayInput === idx ? (
                  <div className="p-2 bg-slate-50 rounded-xl border border-slate-200 mt-2">
                    <input autoFocus placeholder="Task name..." value={newTaskTitle} onChange={(e) => setNewTaskTitle(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAddTask(date)} className="w-full text-xs p-2 bg-white border border-slate-200 rounded-lg outline-none" />
                    <div className="flex justify-end gap-2 mt-2 pt-2 border-t border-slate-100">
                      <button onClick={() => setActiveDayInput(null)} className="text-[10px] font-bold text-slate-400">Cancel</button>
                      <button onClick={() => handleAddTask(date)} className="text-[10px] font-bold text-blue-600">Add</button>
                    </div>
                  </div>
                ) : (
                  <button onClick={() => { setActiveDayInput(idx); setNewTaskTitle(''); }} className="w-full p-2 rounded-xl border border-dashed border-slate-200 text-slate-400 hover:text-[#6B8E7B] hover:border-[#6B8E7B] transition-all flex items-center justify-center gap-1 text-[10px] font-bold mt-2">
                    <Plus size={12} /> ADD
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* WEEKLY REFLECTION SECTION */}
      <section className="bg-white rounded-[40px] border border-slate-200 shadow-2xl shadow-slate-200/50 overflow-hidden">
        <div className="bg-[#1E3A5F] px-12 py-10 text-white flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div className="flex items-center gap-5">
            <div className="p-4 bg-white/10 rounded-2xl backdrop-blur-xl border border-white/10">
              <Brain size={32} className="text-blue-200" />
            </div>
            <div>
              <h3 className="text-3xl font-black tracking-tight">Weekly Reflection</h3>
              <p className="text-blue-100/60 font-medium text-sm">Deep analysis for continuous growth.</p>
            </div>
          </div>
        </div>

        <div className="p-12 grid grid-cols-1 lg:grid-cols-12 gap-12">
          {/* Col 1: State */}
          <div className="lg:col-span-4 space-y-10">
            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Smile size={16} /> Current State</h4>
              <div className="bg-slate-50 p-6 rounded-[32px] space-y-8 border border-slate-100">
                <div className="flex justify-between items-center gap-2">
                  {MOODS.map(m => (
                    <button key={m.label} onClick={() => updateReflection({ mood: m.label })} className={`flex flex-col items-center gap-2 p-3 rounded-2xl transition-all ${reflection.mood === m.label ? 'bg-white shadow-lg scale-110' : 'grayscale hover:grayscale-0'}`}>
                      <span className="text-2xl">{m.emoji}</span>
                      <span className={`text-[9px] font-black uppercase ${reflection.mood === m.label ? m.color : 'text-slate-400'}`}>{m.label}</span>
                    </button>
                  ))}
                </div>
                <div className="space-y-4">
                  <div className="flex justify-between items-center text-xs font-bold text-slate-500"><span>Energy Level</span><span>{reflection.energyLevel}/10</span></div>
                  <input type="range" min="1" max="10" value={reflection.energyLevel} onChange={e => updateReflection({ energyLevel: parseInt(e.target.value) })} className="w-full accent-[#6B8E7B] h-1.5 rounded-full bg-slate-200" />
                </div>
                <div className="space-y-4">
                  <div className="flex justify-between items-center text-xs font-bold text-slate-500"><span>Stress Level</span><span>{reflection.stressLevel}/10</span></div>
                  <input type="range" min="1" max="10" value={reflection.stressLevel} onChange={e => updateReflection({ stressLevel: parseInt(e.target.value) })} className="w-full accent-amber-500 h-1.5 rounded-full bg-slate-200" />
                </div>
              </div>
            </div>
            <div className="space-y-6">
              <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Star size={16} /> Self-Rating</h4>
              <div className="space-y-6 bg-slate-50 p-6 rounded-[32px] border border-slate-100">
                {[{ label: 'Productivity', key: 'productivityRating', color: 'accent-blue-500' }, { label: 'Happiness', key: 'happinessRating', color: 'accent-rose-500' }, { label: 'Balance', key: 'balanceRating', color: 'accent-[#6B8E7B]' }].map(rating => (
                  <div key={rating.key} className="space-y-3">
                    <div className="flex justify-between items-center text-[10px] font-black uppercase text-slate-500"><span>{rating.label}</span><span>{(reflection as any)[rating.key]}/10</span></div>
                    <input type="range" min="1" max="10" value={(reflection as any)[rating.key]} onChange={e => updateReflection({ [rating.key]: parseInt(e.target.value) })} className={`w-full ${rating.color} h-1 rounded-full`} />
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Col 2: Wins */}
