                    <div className={`relative z-10 bg-white rounded-[32px] border ${active ? 'border-blue-400 shadow-xl shadow-blue-50' : 'border-slate-100 shadow-sm'} p-6 flex flex-col sm:flex-row items-center gap-6 transition-all hover:border-blue-200`}>
                      {/* Clock Time Hero */}
                      <div className="flex items-baseline gap-1 shrink-0">
                        <span className={`text-4xl font-black tabular-nums ${active ? 'text-blue-600' : 'text-slate-900'}`}>
