              <div className="space-y-4">
                {topPriorities.length > 0 ? topPriorities.map(task => (
                  <div key={task.id} className="bg-white/10 backdrop-blur-xl border border-white/10 p-6 rounded-3xl flex items-center justify-between group transition-all hover:bg-white/20">
                    <div className="flex items-center gap-5">
                      <button onClick={() => toggleTask(task.id)} className={`w-8 h-8 rounded-xl border-2 flex items-center justify-center transition-all ${task.completed ? 'bg-green-500 border-green-500 text-white' : 'border-white/30 hover:border-white'}`}>
                        {task.completed ? <CheckCircle2 size={18} /> : <Circle size={18} className="text-transparent" />}
                      </button>
                      <p className={`text-lg font-bold ${task.completed ? 'line-through text-white/40' : 'text-white'}`}>{task.title}</p>
                    </div>
                  </div>
                )) : <p className="text-white/40 font-bold italic py-4">Zero high-priority actions logged.</p>}
              </div>
            </div>
          </div>

          {/* Leakages & Focus */}
          <div className="bg-white p-10 rounded-[40px] border border-slate-200 shadow-sm">
             <div className="flex items-center justify-between mb-8">
               <h3 className="text-xl font-black text-slate-900 flex items-center gap-3"><ZapOff size={22} className="text-rose-500" /> Focus Leakages</h3>
               <div className={`text-[10px] font-black px-4 py-2 rounded-full uppercase tracking-widest ${totalDistractionTime > 60 ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>
                 {totalDistractionTime}m Wasted
               </div>
             </div>
             <div className="space-y-3">
               {dailyData.distractions.map(d => (
                 <div key={d.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl group transition-all hover:border-rose-200 border border-transparent">
                   <div className="flex items-center gap-4 text-slate-700">
                     <AlertCircle size={16} className="text-rose-400" />
                     <span className="font-bold">{d.type}</span>
                   </div>
                   <div className="flex items-center gap-4">
                     <span className="text-xs font-black text-slate-400">-{d.minutes}m</span>
                     <button onClick={() => removeDistraction(d.id)} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><X size={16} /></button>
                   </div>
                 </div>
               ))}
               <div className="grid grid-cols-1 sm:grid-cols-12 gap-2 pt-6 border-t border-slate-50">
                 <select value={newDistraction.type} onChange={e => setNewDistraction({...newDistraction, type: e.target.value})} className="sm:col-span-6 bg-slate-50 border border-slate-200 rounded-2xl p-3 text-[10px] font-black uppercase text-slate-500 outline-none">
                   {['Social Media', 'YouTube', 'Overthinking', 'Other'].map(t => <option key={t} value={t}>{t}</option>)}
                 </select>
                 <input type="number" value={newDistraction.minutes} onChange={e => setNewDistraction({...newDistraction, minutes: parseInt(e.target.value)})} className="sm:col-span-3 bg-slate-50 border border-slate-200 rounded-2xl text-center font-black text-slate-700 outline-none" />
                 <button onClick={addDistraction} className="sm:col-span-3 bg-rose-500 text-white p-3 rounded-2xl font-black text-[10px] uppercase shadow-lg">Log</button>
               </div>
             </div>
          </div>

          {/* Energy & Score */}
          <div className="bg-white p-10 rounded-[40px] border border-slate-200 shadow-sm space-y-12">
             <div className="grid grid-cols-2 gap-10">
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Sun size={16} className="text-amber-500" /> Morning Energy</h4>
                   <div className="flex items-center gap-4">
                      <input type="range" min="1" max="10" value={dailyData.morningEnergy} onChange={e => updateData({ morningEnergy: parseInt(e.target.value) })} className="flex-1 accent-amber-500 h-2 rounded-full bg-slate-100" />
                      <span className="text-lg font-black text-slate-700">{dailyData.morningEnergy}</span>
                   </div>
                </div>
                <div className="space-y-4">
                   <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Moon size={16} className="text-indigo-500" /> Evening Energy</h4>
                   <div className="flex items-center gap-4">
                      <input type="range" min="1" max="10" value={dailyData.eveningEnergy} onChange={e => updateData({ eveningEnergy: parseInt(e.target.value) })} className="flex-1 accent-indigo-500 h-2 rounded-full bg-slate-100" />
                      <span className="text-lg font-black text-slate-700">{dailyData.eveningEnergy}</span>
                   </div>
                </div>
             </div>
             <div className="space-y-6 pt-10 border-t border-slate-100">
                <div className="flex items-center justify-between">
                   <h3 className="text-lg font-black text-slate-900 uppercase tracking-widest">Efficiency Score</h3>
                   <span className="text-3xl font-black text-blue-600">{dailyData.productivityScore}<span className="text-slate-200">/10</span></span>
                </div>
                <input type="range" min="1" max="10" value={dailyData.productivityScore} onChange={e => updateData({ productivityScore: parseInt(e.target.value) })} className="w-full accent-blue-600 h-2.5 bg-slate-100 rounded-full cursor-pointer" />
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

