  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return (
          <Dashboard 
            goals={goals} 
            tasks={tasks} 
            habits={habits} 
            highlightedId={highlightedId}
            toggleTask={toggleTask} 
            toggleHabit={toggleHabit}
