      case 'execution':
        return (
          <Execution 
            tasks={tasks}
            dailyExecutions={dailyExecutions}
            updateDailyExecution={updateDailyExecution}
            toggleTask={toggleTask}
            addTask={addTask}
          />
        );
      case 'decisions':
        return <Decisions decisions={decisions} calculateScores={calculateDecisionScores} />;
      case 'analytics':
        return <Analytics goals={goals} tasks={tasks} habits={habits} />;
