import React, { useState, useEffect, useRef } from 'react';
import { NAV_ITEMS } from '../constants';
import { View, User, Goal, Task, Decision, DailyExecution, TimeBlock } from '../types';
import { Search, Bell, LogOut, Target, ListTodo, Scale, X, Command, Zap, AlertCircle, Info, CheckCircle2, History, Play } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  currentView: View;
  setView: (view: View) => void;
  user: User;
  goals: Goal[];
  tasks: Task[];
  decisions: Decision[];
  dailyExecutions: { [date: string]: DailyExecution };
  triggerHighlight: (id: string, view?: View) => void;
}

interface Notification {
  id: string;
  type: 'risk' | 'info' | 'success' | 'alert' | 'live';
  title: string;
  message: string;
  timestamp: string;
}

const Layout: React.FC<LayoutProps> = ({ children, currentView, setView, user, goals, tasks, decisions, dailyExecutions, triggerHighlight }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showResults, setShowResults] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [currentTime, setCurrentTime] = useState(new Date());
  const searchRef = useRef<HTMLDivElement>(null);
  const notifRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const lastNotifiedBlockId = useRef<string | null>(null);

  // Update clock every 30 seconds to drive time-based notifications
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 30000);
    return () => clearInterval(timer);
  }, []);

  // Request browser notification permissions on mount
  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }
  }, []);

  // Derived Notifications Logic
  const notifications: Notification[] = React.useMemo(() => {
    const list: Notification[] = [];
    const today = new Date();
    today.setHours(0,0,0,0);
    const todayStr = today.toISOString().split('T')[0];
    const nowHHmm = `${currentTime.getHours().toString().padStart(2, '0')}:${currentTime.getMinutes().toString().padStart(2, '0')}`;

    // 1. Check for Timeline Blocks starting NOW
    const todaysExecution = dailyExecutions[todayStr];
    if (todaysExecution && todaysExecution.timeBlocks) {
      todaysExecution.timeBlocks.forEach(block => {
        // If the block starts now or within the last 5 mins (to ensure it shows up)
        if (block.start === nowHHmm) {
          list.push({
            id: `notif-block-${block.id}-${currentTime.getMinutes()}`,
            type: 'live',
            title: 'Time to Execute',
            message: `Your session "${block.activity}" starts now.`,
            timestamp: 'Just now'
          });

          // Trigger browser notification if block is new
          if (lastNotifiedBlockId.current !== block.id) {
            if ("Notification" in window && Notification.permission === "granted") {
              new Notification("LifeOS: Time to start", {
                body: `Scheduled: ${block.activity}`,
                icon: '/favicon.ico'
              });
            }
            lastNotifiedBlockId.current = block.id;
          }
        }
      });
    }

    // 2. Check for Overdue Goals
    goals.forEach(goal => {
      const target = new Date(goal.targetDate);
      target.setHours(0,0,0,0);
      if (target < today && goal.progress < 100) {
        list.push({
          id: `notif-goal-${goal.id}`,
          type: 'risk',
          title: 'Goal Overdue',
          message: `"${goal.title}" has passed its deadline.`,
          timestamp: 'Action Required'
        });
      }
    });

    // 3. Persistent Task Notifications
    tasks.forEach(task => {
      const taskDate = new Date(task.date);
      taskDate.setHours(0,0,0,0);
      const isPastTask = taskDate.getTime() < today.getTime();

      if (!task.completed && (task.isCarriedForward || isPastTask)) {
        list.push({
          id: `notif-task-carried-${task.id}`,
          type: 'alert',
          title: 'Pending Action',
          message: `"${task.title}" rolled over. Focus here.`,
          timestamp: 'Persistent'
        });
      }
    });

    return list;
  }, [goals, tasks, dailyExecutions, currentTime]);

  // Handle keyboard shortcut (⌘K or Ctrl+K)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        inputRef.current?.focus();
      }
      if (e.key === 'Escape') {
        setShowResults(false);
        setShowNotifications(false);
        inputRef.current?.blur();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  // Close overlays when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(e.target as Node)) {
        setShowResults(false);
      }
      if (notifRef.current && !notifRef.current.contains(e.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Filter logic for Search
  const filteredGoals = searchTerm.trim() 
    ? goals.filter(g => g.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];
  const filteredTasks = searchTerm.trim() 
    ? tasks.filter(t => t.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];
  const filteredDecisions = searchTerm.trim() 
    ? decisions.filter(d => d.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];

  const filteredNav = searchTerm.trim()
    ? NAV_ITEMS.filter(item => item.label.toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  const totalResults = filteredGoals.length + filteredTasks.length + filteredDecisions.length + filteredNav.length;

  const handleItemSelect = (id: string, view: View) => {
    triggerHighlight(id, view);
    setSearchTerm('');
    setShowResults(false);
  };

  const handleNavSelect = (view: View) => {
    setView(view);
    setSearchTerm('');
    setShowResults(false);
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#F4F4F2]">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-200 flex flex-col z-20">
        <div className="p-6">
          <div className="flex items-center gap-2 mb-8">
            <div className="w-8 h-8 bg-[#6B8E7B] rounded-lg flex items-center justify-center text-white font-bold shadow-sm">L</div>
            <h1 className="text-xl font-black tracking-tight text-slate-800">LifeOS</h1>
          </div>

          <nav className="space-y-1">
            {NAV_ITEMS.map((item) => (
              <button
                key={item.id}
                onClick={() => setView(item.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 ${
                  currentView === item.id 
                    ? 'bg-[#1E3A5F] text-white shadow-lg shadow-blue-900/10' 
                    : 'text-slate-500 hover:bg-slate-100 hover:text-slate-900'
                }`}
              >
                {item.icon}
                <span className="font-bold text-sm tracking-tight">{item.label}</span>
              </button>
            ))}
          </nav>
        </div>

        <div className="mt-auto p-4 border-t border-slate-100">
          <div className="flex items-center gap-3 p-2 rounded-xl bg-slate-50 border border-slate-100">
            <img src={user.avatar} alt={user.name} className="w-10 h-10 rounded-full border-2 border-white" />
            <div className="overflow-hidden">
              <p className="text-xs font-black text-slate-900 truncate">{user.name}</p>
              <p className="text-[10px] text-slate-400 font-bold truncate uppercase tracking-tighter">{user.email}</p>
            </div>
            <button className="ml-auto text-slate-400 hover:text-slate-600">
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col relative z-10 overflow-hidden">
        {/* Top Header */}
