                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <ListTodo size={16} className="text-[#6B8E7B]" />
                            <span className="text-sm font-medium text-slate-700 group-hover:text-[#6B8E7B]">{t.title}</span>
                          </button>
                        ))}
                      </div>
                    )}

                    {filteredDecisions.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Decisions</div>
                        {filteredDecisions.map(d => (
                          <button 
                            key={d.id} 
                            onClick={() => handleItemSelect(d.id, 'decisions')}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <Scale size={16} className="text-orange-500" />
                            <span className="text-sm font-medium text-slate-700 group-hover:text-orange-600">{d.title}</span>
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                )}
                <div className="bg-slate-50 px-4 py-2 border-t border-slate-100 flex items-center justify-between">
                   <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-400 uppercase">
                     <Command size={10} /> + K to focus
                   </div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase">
                     ESC to close
                   </div>
                </div>
              </div>
            )}
          </div>

          <div className="flex items-center gap-4">
            <div className="relative" ref={notifRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className={`p-2 rounded-full transition-colors relative ${showNotifications ? 'bg-slate-100 text-[#1E3A5F]' : 'text-slate-500 hover:bg-slate-100'}`}
              >
                <Bell size={20} />
                {notifications.length > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-blue-600 rounded-full border-2 border-white flex items-center justify-center text-[8px] font-bold text-white animate-pulse">
                    {notifications.length}
                  </span>
                )}
              </button>

              {/* Notifications Panel */}
              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200 z-50">
                  <div className="px-6 py-5 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                    <h3 className="font-black text-slate-900 text-sm tracking-tight">System Alerts</h3>
                    <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-2 py-1 rounded-full uppercase tracking-widest">
                      {notifications.length > 0 ? `${notifications.length} Unread` : 'Clear'}
                    </span>
                  </div>
                  <div className="max-h-[400px] overflow-y-auto divide-y divide-slate-100">
                    {notifications.length === 0 ? (
                      <div className="p-10 text-center">
                        <CheckCircle2 size={32} className="text-slate-200 mx-auto mb-2" />
                        <p className="text-slate-400 text-sm font-medium">All systems clear.</p>
                      </div>
                    ) : (
                      notifications.map(notif => (
                        <div 
                          key={notif.id} 
                          className="p-5 hover:bg-slate-50 transition-colors flex gap-4 cursor-pointer group"
                          onClick={() => {
                             if (notif.id.includes('goal')) handleItemSelect(notif.id.split('-goal-')[1], 'vision');
                             if (notif.id.includes('task')) handleItemSelect(notif.id.split('-task-carried-')[1], 'planner');
                             if (notif.id.includes('block')) handleItemSelect('', 'execution');
                             setShowNotifications(false);
                          }}
                        >
                          <div className={`mt-0.5 p-2 rounded-xl shrink-0 ${
                            notif.type === 'risk' ? 'bg-red-50 text-red-600' : 
                            notif.type === 'alert' ? 'bg-amber-50 text-amber-600' :
                            notif.type === 'live' ? 'bg-blue-600 text-white animate-pulse' :
                            'bg-blue-50 text-blue-600'
                          }`}>
                            {notif.type === 'risk' ? <AlertCircle size={16} /> : 
                             notif.type === 'alert' ? <History size={16} /> : 
                             notif.type === 'live' ? <Play size={16} fill="currentColor" /> :
                             <Info size={16} />}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex justify-between items-start gap-2">
                              <p className="text-sm font-black text-slate-900 leading-tight group-hover:text-blue-600 transition-colors">{notif.title}</p>
                              <span className="text-[9px] text-slate-400 font-black uppercase shrink-0 tracking-tighter">{notif.timestamp}</span>
                            </div>
                            <p className="text-xs text-slate-500 mt-1 leading-relaxed font-medium">{notif.message}</p>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                  <div className="px-6 py-4 border-t border-slate-100 bg-slate-50/50 text-center">
                    <button className="text-[10px] font-black text-slate-400 hover:text-slate-600 uppercase tracking-[0.2em]">Historical Log</button>
                  </div>
                </div>
              )}
            </div>

            <div className="h-8 w-px bg-slate-200 mx-2"></div>
            <button 
              onClick={() => { inputRef.current?.focus(); }}
              className="bg-[#1E3A5F] hover:bg-blue-900 text-white px-5 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-md active:scale-95"
            >
              Command
            </button>
          </div>
        </header>

        {/* Scrollable View Area */}
        <div className="flex-1 overflow-y-auto p-8 bg-[#F4F4F2]/50 scroll-smooth">
          <div className="max-w-6xl mx-auto animate-in fade-in slide-in-from-bottom-2 duration-500">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useRef } from 'react';
import { NAV_ITEMS } from '../constants';
import { View, User, Goal, Task, Decision, DailyExecution, TimeBlock } from '../types';
import { Search, Bell, LogOut, Target, ListTodo, Scale, X, Command, Zap, AlertCircle, Info, CheckCircle2, History, Play, BellRing } from 'lucide-react';

interface LayoutProps {
  children: React.Node;
  currentView: View;
  setView: (view: View) => void;
  user: User;
  goals: Goal[];
  tasks: Task[];
  decisions: Decision[];
  dailyExecutions: { [date: string]: DailyExecution };
  triggerHighlight: (id: string, view?: View) => void;
}

interface Notification {
  id: string;
  type: 'risk' | 'info' | 'success' | 'alert' | 'live';
  title: string;
  message: string;
  timestamp: string;
}

interface Toast {
  id: string;
  title: string;
  message: string;
  type: 'live' | 'info';
}

const Layout: React.FC<LayoutProps> = ({ children, currentView, setView, user, goals, tasks, decisions, dailyExecutions, triggerHighlight }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showResults, setShowResults] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [currentTime, setCurrentTime] = useState(new Date());
  const [activeToast, setActiveToast] = useState<Toast | null>(null);
  const searchRef = useRef<HTMLDivElement>(null);
  const notifRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const lastNotifiedBlockId = useRef<string | null>(null);

  // Update clock every 10 seconds for more responsive "start time" detection
  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 10000);
    return () => clearInterval(timer);
  }, []);

  // Browser notification permission
  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission();
    }
  }, []);

  // Toast auto-dismiss
  useEffect(() => {
    if (activeToast) {
      const timer = setTimeout(() => setActiveToast(null), 8000);
      return () => clearTimeout(timer);
    }
  }, [activeToast]);

  // Derived Notifications and Toast Logic
  useEffect(() => {
    const today = new Date();
    today.setHours(0,0,0,0);
    const todayStr = today.toISOString().split('T')[0];
    const nowHHmm = `${currentTime.getHours().toString().padStart(2, '0')}:${currentTime.getMinutes().toString().padStart(2, '0')}`;

    const todaysExecution = dailyExecutions[todayStr];
    if (todaysExecution && todaysExecution.timeBlocks) {
      const currentBlock = todaysExecution.timeBlocks.find(block => block.start === nowHHmm);

      if (currentBlock && lastNotifiedBlockId.current !== currentBlock.id) {
        // Trigger Toast
        setActiveToast({
          id: `toast-${currentBlock.id}`,
          title: 'Time to Start!',
          message: `Scheduled activity: ${currentBlock.activity}`,
          type: 'live'
        });

        // Trigger Browser Notification
        if ("Notification" in window && Notification.permission === "granted") {
          new Notification("LifeOS: Time to start", {
            body: `Starting: ${currentBlock.activity}`,
            icon: '/favicon.ico'
          });
        }

        lastNotifiedBlockId.current = currentBlock.id;
      }
    }
  }, [currentTime, dailyExecutions]);

  // Persistent System Notifications
  const notifications: Notification[] = React.useMemo(() => {
    const list: Notification[] = [];
    const today = new Date();
    today.setHours(0,0,0,0);
    const todayStr = today.toISOString().split('T')[0];
    const nowHHmm = `${currentTime.getHours().toString().padStart(2, '0')}:${currentTime.getMinutes().toString().padStart(2, '0')}`;

    // 1. Current Live Block
    const todaysExecution = dailyExecutions[todayStr];
    if (todaysExecution && todaysExecution.timeBlocks) {
      todaysExecution.timeBlocks.forEach(block => {
        if (block.start === nowHHmm) {
          list.push({
            id: `notif-block-${block.id}`,
            type: 'live',
            title: 'Active Session',
            message: `Current: ${block.activity}`,
            timestamp: 'LIVE'
          });
        }
      });
    }

    // 2. Overdue Goals
    goals.forEach(goal => {
      const target = new Date(goal.targetDate);
      target.setHours(0,0,0,0);
      if (target < today && goal.progress < 100) {
        list.push({
          id: `notif-goal-${goal.id}`,
          type: 'risk',
          title: 'Goal Overdue',
          message: `"${goal.title}" deadline passed.`,
          timestamp: 'Alert'
        });
      }
    });

    return list;
  }, [goals, dailyExecutions, currentTime]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        inputRef.current?.focus();
      }
      if (e.key === 'Escape') {
        setShowResults(false);
        setShowNotifications(false);
        inputRef.current?.blur();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(e.target as Node)) {
        setShowResults(false);
      }
      if (notifRef.current && !notifRef.current.contains(e.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const filteredGoals = searchTerm.trim() 
    ? goals.filter(g => g.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];
  const filteredTasks = searchTerm.trim() 
    ? tasks.filter(t => t.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];
  const filteredDecisions = searchTerm.trim() 
    ? decisions.filter(d => d.title.toLowerCase().includes(searchTerm.toLowerCase())) 
    : [];

  const filteredNav = searchTerm.trim()
    ? NAV_ITEMS.filter(item => item.label.toLowerCase().includes(searchTerm.toLowerCase()))
    : [];

  const totalResults = filteredGoals.length + filteredTasks.length + filteredDecisions.length + filteredNav.length;

  const handleItemSelect = (id: string, view: View) => {
    triggerHighlight(id, view);
    setSearchTerm('');
    setShowResults(false);
  };

  const handleNavSelect = (view: View) => {
    setView(view);
    setSearchTerm('');
    setShowResults(false);
  };

  return (
    <div className="flex h-screen overflow-hidden bg-[#F4F4F2]">
      {/* Toast Notification Layer */}
      {activeToast && (
        <div className="fixed top-6 right-6 z-[100] w-80 animate-in slide-in-from-right-8 duration-500">
          <div className="bg-white rounded-[24px] shadow-2xl border border-blue-100 p-5 flex gap-4 overflow-hidden relative group">
            <div className="absolute top-0 left-0 w-1 h-full bg-blue-600 animate-pulse"></div>
            <div className="p-3 bg-blue-600 rounded-2xl text-white shrink-0 shadow-lg shadow-blue-200">
              <BellRing size={20} className="animate-bounce" />
            </div>
            <div className="flex-1">
              <div className="flex items-center justify-between mb-1">
                <h5 className="text-xs font-black text-blue-600 uppercase tracking-widest">{activeToast.title}</h5>
                <button onClick={() => setActiveToast(null)} className="text-slate-300 hover:text-slate-500">
                  <X size={14} />
                </button>
              </div>
              <p className="text-sm font-bold text-slate-800 leading-tight mb-3">{activeToast.message}</p>
              <button 
                onClick={() => { setView('execution'); setActiveToast(null); }}
                className="w-full bg-slate-50 hover:bg-slate-100 text-[10px] font-black text-slate-500 py-2 rounded-xl uppercase tracking-widest transition-all"
              >
                Go to Execution View
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-slate-200 flex flex-col z-20">
        <div className="p-6">
          <div className="flex items-center gap-2 mb-8">
            <div className="w-8 h-8 bg-[#6B8E7B] rounded-lg flex items-center justify-center text-white font-bold shadow-sm">L</div>
            <h1 className="text-xl font-black tracking-tight text-slate-800">LifeOS</h1>
          </div>

          <nav className="space-y-1">
            {NAV_ITEMS.map((item) => (
              <button
                key={item.id}
                onClick={() => setView(item.id)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all duration-200 ${
                  currentView === item.id 
                    ? 'bg-[#1E3A5F] text-white shadow-lg shadow-blue-900/10' 
                    : 'text-slate-500 hover:bg-slate-100 hover:text-slate-900'
                }`}
              >
                {item.icon}
                <span className="font-bold text-sm tracking-tight">{item.label}</span>
              </button>
            ))}
          </nav>
        </div>

        <div className="mt-auto p-4 border-t border-slate-100">
          <div className="flex items-center gap-3 p-2 rounded-xl bg-slate-50 border border-slate-100">
            <img src={user.avatar} alt={user.name} className="w-10 h-10 rounded-full border-2 border-white" />
            <div className="overflow-hidden">
              <p className="text-xs font-black text-slate-900 truncate">{user.name}</p>
              <p className="text-[10px] text-slate-400 font-bold truncate uppercase tracking-tighter">{user.email}</p>
            </div>
            <button className="ml-auto text-slate-400 hover:text-slate-600">
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col relative z-10 overflow-hidden">
        {/* Top Header */}
        <header className="h-16 bg-white/80 backdrop-blur-md border-b border-slate-200 px-8 flex items-center justify-between sticky top-0 z-30">
          <div className="relative w-96" ref={searchRef}>
            <div className="flex items-center gap-4 bg-slate-100 px-4 py-2 rounded-full border border-slate-200 group focus-within:ring-2 focus-within:ring-[#6B8E7B]/20 focus-within:border-[#6B8E7B] transition-all">
              <Search size={18} className="text-slate-400 group-focus-within:text-[#6B8E7B]" />
              <input 
                ref={inputRef}
                type="text" 
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setShowResults(true);
                }}
                onFocus={() => setShowResults(true)}
                placeholder="Find goals, tasks, or views... (⌘K)" 
                className="bg-transparent border-none outline-none text-sm w-full font-medium"
              />
              {searchTerm && (
                <button onClick={() => setSearchTerm('')} className="text-slate-400 hover:text-slate-600">
                  <X size={14} />
                </button>
              )}
            </div>

            {/* Search Results Dropdown */}
            {showResults && searchTerm && (
              <div className="absolute top-full mt-2 w-full bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200 max-h-[400px] overflow-y-auto">
                {totalResults === 0 ? (
                  <div className="p-8 text-center">
                    <p className="text-slate-400 text-sm font-medium">No results found for "{searchTerm}"</p>
                  </div>
                ) : (
                  <div className="p-2 space-y-4">
                    {filteredNav.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">App Sections</div>
                        {filteredNav.map(item => (
                          <button 
                            key={item.id} 
                            onClick={() => handleNavSelect(item.id)}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <Zap size={16} className="text-purple-500" />
                            <span className="text-sm font-bold text-slate-700 group-hover:text-purple-600">{item.label}</span>
                          </button>
                        ))}
                      </div>
                    )}

                    {filteredGoals.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Strategic Goals</div>
                        {filteredGoals.map(g => (
                          <button 
                            key={g.id} 
                            onClick={() => handleItemSelect(g.id, 'vision')}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <Target size={16} className="text-blue-500" />
                            <span className="text-sm font-medium text-slate-700 group-hover:text-blue-600">{g.title}</span>
                          </button>
                        ))}
                      </div>
                    )}

                    {filteredTasks.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Active Tasks</div>
                        {filteredTasks.map(t => (
                          <button 
                            key={t.id} 
                            onClick={() => handleItemSelect(t.id, 'dashboard')}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <ListTodo size={16} className="text-[#6B8E7B]" />
                            <span className="text-sm font-medium text-slate-700 group-hover:text-[#6B8E7B]">{t.title}</span>
                          </button>
                        ))}
                      </div>
                    )}

                    {filteredDecisions.length > 0 && (
                      <div>
                        <div className="px-3 py-1 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Decisions</div>
                        {filteredDecisions.map(d => (
                          <button 
                            key={d.id} 
                            onClick={() => handleItemSelect(d.id, 'decisions')}
                            className="w-full flex items-center gap-3 px-3 py-2 hover:bg-slate-50 rounded-xl transition-colors text-left group"
                          >
                            <Scale size={16} className="text-orange-500" />
                            <span className="text-sm font-medium text-slate-700 group-hover:text-orange-600">{d.title}</span>
                          </button>
                        ))}
                      </div>
                    )}
                  </div>
                )}
                <div className="bg-slate-50 px-4 py-2 border-t border-slate-100 flex items-center justify-between">
                   <div className="flex items-center gap-1.5 text-[10px] font-bold text-slate-400 uppercase">
                     <Command size={10} /> + K to focus
                   </div>
                   <div className="text-[10px] font-bold text-slate-400 uppercase">
                     ESC to close
                   </div>
                </div>
              </div>
            )}
          </div>

          <div className="flex items-center gap-4">
            <div className="relative" ref={notifRef}>
              <button 
                onClick={() => setShowNotifications(!showNotifications)}
                className={`p-2 rounded-full transition-colors relative ${showNotifications ? 'bg-slate-100 text-[#1E3A5F]' : 'text-slate-500 hover:bg-slate-100'}`}
              >
                <Bell size={20} />
                {notifications.length > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-blue-600 rounded-full border-2 border-white flex items-center justify-center text-[8px] font-bold text-white animate-pulse">
                    {notifications.length}
                  </span>
                )}
              </button>

              {/* Notifications Panel */}
              {showNotifications && (
                <div className="absolute right-0 mt-3 w-80 bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200 z-50">
                  <div className="px-6 py-5 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
                    <h3 className="font-black text-slate-900 text-sm tracking-tight">System Alerts</h3>
                    <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-2 py-1 rounded-full uppercase tracking-widest">
                      {notifications.length > 0 ? `${notifications.length} Unread` : 'Clear'}
                    </span>
                  </div>
                  <div className="max-h-[400px] overflow-y-auto divide-y divide-slate-100">
                    {notifications.length === 0 ? (
                      <div className="p-10 text-center">
                        <CheckCircle2 size={32} className="text-slate-200 mx-auto mb-2" />
                        <p className="text-slate-400 text-sm font-medium">All systems clear.</p>
                      </div>
                    ) : (
                      notifications.map(notif => (
                        <div 
                          key={notif.id} 
                          className="p-5 hover:bg-slate-50 transition-colors flex gap-4 cursor-pointer group"
                          onClick={() => {
                             if (notif.id.includes('goal')) handleItemSelect(notif.id.split('-goal-')[1], 'vision');
                             if (notif.id.includes('block')) handleItemSelect('', 'execution');
                             setShowNotifications(false);
                          }}
                        >
                          <div className={`mt-0.5 p-2 rounded-xl shrink-0 ${
                            notif.type === 'risk' ? 'bg-red-50 text-red-600' : 
                            notif.type === 'alert' ? 'bg-amber-50 text-amber-600' :
                            notif.type === 'live' ? 'bg-blue-600 text-white animate-pulse' :
                            'bg-blue-50 text-blue-600'
                          }`}>
                            {notif.type === 'risk' ? <AlertCircle size={16} /> : 
                             notif.type === 'alert' ? <History size={16} /> : 
                             notif.type === 'live' ? <Play size={16} fill="currentColor" /> :
                             <Info size={16} />}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex justify-between items-start gap-2">
                              <p className="text-sm font-black text-slate-900 leading-tight group-hover:text-blue-600 transition-colors">{notif.title}</p>
                              <span className="text-[9px] text-slate-400 font-black uppercase shrink-0 tracking-tighter">{notif.timestamp}</span>
                            </div>
                            <p className="text-xs text-slate-500 mt-1 leading-relaxed font-medium">{notif.message}</p>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                  <div className="px-6 py-4 border-t border-slate-100 bg-slate-50/50 text-center">
                    <button className="text-[10px] font-black text-slate-400 hover:text-slate-600 uppercase tracking-[0.2em]">Historical Log</button>
                  </div>
                </div>
              )}
            </div>

            <div className="h-8 w-px bg-slate-200 mx-2"></div>
            <button 
              onClick={() => { inputRef.current?.focus(); }}
              className="bg-[#1E3A5F] hover:bg-blue-900 text-white px-5 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-md active:scale-95"
            >
              Command
            </button>
          </div>
        </header>

        {/* Scrollable View Area */}
        <div className="flex-1 overflow-y-auto p-8 bg-[#F4F4F2]/50 scroll-smooth">
          <div className="max-w-6xl mx-auto animate-in fade-in slide-in-from-bottom-2 duration-500">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
};

export default Layout;

